-- ============================================================
-- Quiz Seed: Genesis Chapters 1–25
-- Target table: chapter_quizzes
-- Difficulties: kids (3 Qs), teens (5 Qs), adults (8 Qs)
-- ============================================================

-- ═══════════════════════════════════════════
-- CHAPTERS 1 – 5
-- ═══════════════════════════════════════════

-- ═══ Genesis Chapter 1 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Genesis', 1, 'kids', 1, 'What did God create on the very first day?', 'Light', 'Water', 'Animals', 'Stars', 'a', 'God said "Let there be light" and there was light (Genesis 1:3).'),
('Genesis', 1, 'kids', 2, 'What did God make on Day 6?', 'Fish', 'Stars', 'Man and animals', 'Birds', 'c', 'God made land animals and man on the sixth day (Genesis 1:24-27).'),
('Genesis', 1, 'kids', 3, 'How many days did it take God to create everything?', '3 days', '6 days', '10 days', '1 day', 'b', 'God created everything in six days and rested on the seventh (Genesis 1:31–2:2).'),
-- Teens
('Genesis', 1, 'teens', 1, 'What did God create on the second day?', 'Dry land and seas', 'The firmament dividing the waters', 'The sun and the moon', 'Sea creatures and birds', 'b', 'God made the firmament and divided the waters above from the waters beneath (Genesis 1:6-8).'),
('Genesis', 1, 'teens', 2, 'On which day did God create the sun, moon, and stars?', 'Day 1', 'Day 3', 'Day 4', 'Day 5', 'c', 'God made two great lights and the stars on the fourth day (Genesis 1:14-19).'),
('Genesis', 1, 'teens', 3, 'What did God say about everything He had made at the end of Day 6?', 'It was good', 'It was very good', 'It was finished', 'It was holy', 'b', 'God saw every thing that he had made, and behold, it was very good (Genesis 1:31).'),
('Genesis', 1, 'teens', 4, 'In whose image was man created?', 'The angels'' image', 'God''s image', 'The animals'' image', 'Adam''s image', 'b', 'God said, "Let us make man in our image, after our likeness" (Genesis 1:26).'),
('Genesis', 1, 'teens', 5, 'What was man given dominion over?', 'Only the land animals', 'The fish, birds, and every living thing', 'Only the garden of Eden', 'The earth and the heavens', 'b', 'God gave man dominion over the fish, fowl, cattle, and every creeping thing (Genesis 1:26, 28).'),
-- Adults
('Genesis', 1, 'adults', 1, 'What phrase is used in Genesis 1:2 to describe the state of the earth before creation?', 'Dark and void', 'Empty and barren', 'Without form, and void', 'Shapeless and desolate', 'c', 'The earth was without form, and void; and darkness was upon the face of the deep (Genesis 1:2).'),
('Genesis', 1, 'adults', 2, 'What moved upon the face of the waters in Genesis 1:2?', 'A mighty wind', 'The Spirit of God', 'The hand of God', 'An angel of the Lord', 'b', 'And the Spirit of God moved upon the face of the waters (Genesis 1:2).'),
('Genesis', 1, 'adults', 3, 'What did God call the firmament?', 'Sky', 'Heaven', 'Air', 'Expanse', 'b', 'And God called the firmament Heaven (Genesis 1:8).'),
('Genesis', 1, 'adults', 4, 'On which day were seed-bearing herbs and fruit trees created?', 'Day 2', 'Day 3', 'Day 4', 'Day 5', 'b', 'On the third day God said, "Let the earth bring forth grass, the herb yielding seed, and the fruit tree" (Genesis 1:11-13).'),
('Genesis', 1, 'adults', 5, 'What two purposes did God assign to the lights in the firmament?', 'To give warmth and beauty', 'To divide the day from the night and for signs, seasons, days, and years', 'To shine upon the earth and to guide travelers', 'To rule the angels and to mark holy days', 'b', 'God said let them be for signs, and for seasons, and for days, and years, and to divide the day from the night (Genesis 1:14).'),
('Genesis', 1, 'adults', 6, 'What Hebrew word is translated "God" throughout Genesis 1?', 'Yahweh', 'Adonai', 'Elohim', 'El Shaddai', 'c', 'The Hebrew word used for God in Genesis 1 is Elohim, a plural noun conveying majesty.'),
('Genesis', 1, 'adults', 7, 'What specific blessing did God give to the sea creatures and birds on Day 5?', 'Dominion over the earth', 'Be fruitful, and multiply', 'Eternal life', 'Knowledge of good and evil', 'b', 'And God blessed them, saying, Be fruitful, and multiply (Genesis 1:22).'),
('Genesis', 1, 'adults', 8, 'What does Genesis 1:26 reveal by using the phrase "Let us make man in our image"?', 'God was speaking to the animals', 'A plurality within the Godhead', 'God was uncertain about creation', 'God was addressing the heavens', 'b', 'The plural "us" and "our" in Genesis 1:26 has traditionally been understood as reflecting the Trinity or a divine plurality.');

-- ═══ Genesis Chapter 2 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Genesis', 2, 'kids', 1, 'What did God do on the seventh day?', 'He made more animals', 'He rested', 'He made the stars', 'He planted flowers', 'b', 'God rested on the seventh day from all his work (Genesis 2:2).'),
('Genesis', 2, 'kids', 2, 'What was the name of the garden God made for Adam?', 'Garden of Flowers', 'Garden of Eden', 'Garden of Paradise', 'Garden of Heaven', 'b', 'God planted a garden eastward in Eden (Genesis 2:8).'),
('Genesis', 2, 'kids', 3, 'How did God make Eve?', 'From the dust', 'From a flower', 'From one of Adam''s ribs', 'From the water', 'c', 'God took one of Adam''s ribs and made a woman (Genesis 2:21-22).'),
-- Teens
('Genesis', 2, 'teens', 1, 'What job did God give Adam in the garden?', 'To build a house', 'To dress it and keep it', 'To rule over all the nations', 'To name the plants', 'b', 'God put Adam in the garden to dress it and to keep it (Genesis 2:15).'),
('Genesis', 2, 'teens', 2, 'Which tree were Adam and Eve forbidden to eat from?', 'The tree of life', 'The tree of knowledge of good and evil', 'The fig tree', 'The olive tree', 'b', 'God commanded not to eat of the tree of the knowledge of good and evil (Genesis 2:17).'),
('Genesis', 2, 'teens', 3, 'What did God say would happen if Adam ate from the forbidden tree?', 'He would become a god', 'He would lose his memory', 'He would surely die', 'He would leave the garden', 'c', 'God said, "In the day that thou eatest thereof thou shalt surely die" (Genesis 2:17).'),
('Genesis', 2, 'teens', 4, 'Why did God decide to make Eve?', 'Adam asked for a companion', 'God said it was not good for man to be alone', 'The animals needed a caretaker', 'Adam was lonely and cried', 'b', 'God said, "It is not good that the man should be alone; I will make him an help meet" (Genesis 2:18).'),
('Genesis', 2, 'teens', 5, 'What task did Adam perform that showed his authority over the animals?', 'He fed them', 'He trained them', 'He gave them names', 'He built shelters for them', 'c', 'Adam gave names to all cattle, fowl, and every beast of the field (Genesis 2:20).'),
-- Adults
('Genesis', 2, 'adults', 1, 'From what material did God form man?', 'Clay from the river', 'Dust of the ground', 'Soil from Eden', 'Stone from the mountain', 'b', 'The LORD God formed man of the dust of the ground (Genesis 2:7).'),
('Genesis', 2, 'adults', 2, 'What did God breathe into man''s nostrils?', 'The Holy Spirit', 'Life and knowledge', 'The breath of life', 'Wisdom and understanding', 'c', 'God breathed into his nostrils the breath of life; and man became a living soul (Genesis 2:7).'),
('Genesis', 2, 'adults', 3, 'How many rivers branched from the river that went out of Eden?', 'Two', 'Three', 'Four', 'Seven', 'c', 'A river went out of Eden and parted into four heads (Genesis 2:10).'),
('Genesis', 2, 'adults', 4, 'Which of these is one of the four rivers named in Genesis 2?', 'Jordan', 'Nile', 'Euphrates', 'Galilee', 'c', 'The four rivers are Pison, Gihon, Hiddekel (Tigris), and Euphrates (Genesis 2:11-14).'),
('Genesis', 2, 'adults', 5, 'What was the name of the land associated with gold and bdellium?', 'Eden', 'Havilah', 'Canaan', 'Shinar', 'b', 'The land of Havilah, where there is gold, and bdellium and the onyx stone (Genesis 2:11-12).'),
('Genesis', 2, 'adults', 6, 'What foundational statement about marriage appears in Genesis 2:24?', 'A man shall honor his father and mother', 'A man shall leave his father and mother and cleave unto his wife', 'A man shall take a wife from his own people', 'A man and his wife shall multiply and fill the earth', 'b', 'Therefore shall a man leave his father and his mother, and shall cleave unto his wife: and they shall be one flesh (Genesis 2:24).'),
('Genesis', 2, 'adults', 7, 'What was the condition of Adam and Eve described in the last verse of chapter 2?', 'They were fearful and hiding', 'They were naked and not ashamed', 'They were clothed in light', 'They were walking with God', 'b', 'They were both naked, the man and his wife, and were not ashamed (Genesis 2:25).'),
('Genesis', 2, 'adults', 8, 'What significant theological truth is established by Adam finding no suitable helper among the animals?', 'Animals are inferior to humans', 'Man''s unique nature requires a companion of equal dignity', 'God made a mistake in creating animals first', 'Adam was not satisfied with God''s creation', 'b', 'No suitable helper was found among the animals, showing that man needed a companion of his own kind, made in God''s image (Genesis 2:20).');

-- ═══ Genesis Chapter 3 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Genesis', 3, 'kids', 1, 'Which animal tricked Eve in the garden?', 'A lion', 'A serpent', 'A bird', 'A fox', 'b', 'The serpent was more subtil than any beast of the field and spoke to Eve (Genesis 3:1).'),
('Genesis', 3, 'kids', 2, 'What did Adam and Eve do after they ate the forbidden fruit?', 'They ran away from the garden', 'They hid from God', 'They went to sleep', 'They planted more trees', 'b', 'Adam and his wife hid themselves from the presence of the LORD God (Genesis 3:8).'),
('Genesis', 3, 'kids', 3, 'What did God use to make clothes for Adam and Eve?', 'Leaves', 'Cotton', 'Coats of animal skins', 'Wool', 'c', 'God made coats of skins and clothed them (Genesis 3:21).'),
-- Teens
('Genesis', 3, 'teens', 1, 'What lie did the serpent tell Eve about eating the fruit?', 'You will become sick', 'You shall not surely die', 'You will turn into an animal', 'You will forget everything', 'b', 'The serpent said, "Ye shall not surely die" (Genesis 3:4).'),
('Genesis', 3, 'teens', 2, 'What were the three things Eve saw about the forbidden tree that tempted her?', 'It was tall, green, and beautiful', 'It was good for food, pleasant to the eyes, and desired to make one wise', 'It was sweet, large, and colorful', 'It was near, ripe, and fragrant', 'b', 'The woman saw that the tree was good for food, pleasant to the eyes, and desired to make one wise (Genesis 3:6).'),
('Genesis', 3, 'teens', 3, 'What did Adam and Eve make to cover themselves?', 'Coats of animal fur', 'Aprons of fig leaves', 'Robes of linen', 'Coverings of bark', 'b', 'They sewed fig leaves together, and made themselves aprons (Genesis 3:7).'),
('Genesis', 3, 'teens', 4, 'What was part of the curse on the woman?', 'She would never have children', 'She would have sorrow in childbearing', 'She could never return to Eden', 'She would lose her speech', 'b', 'God said, "I will greatly multiply thy sorrow and thy conception; in sorrow thou shalt bring forth children" (Genesis 3:16).'),
('Genesis', 3, 'teens', 5, 'What was placed at the east of the garden of Eden to guard the tree of life?', 'A wall of fire', 'An angel with a sword', 'Cherubims and a flaming sword', 'A deep river', 'c', 'God placed Cherubims, and a flaming sword which turned every way, to keep the way of the tree of life (Genesis 3:24).'),
-- Adults
('Genesis', 3, 'adults', 1, 'What is the serpent described as in Genesis 3:1?', 'The most dangerous beast', 'More subtil than any beast of the field', 'The most beautiful creature', 'The oldest animal in the garden', 'b', 'Now the serpent was more subtil than any beast of the field which the LORD God had made (Genesis 3:1).'),
('Genesis', 3, 'adults', 2, 'What is the theological significance of Genesis 3:15, often called the protoevangelium?', 'It establishes the Sabbath', 'It is the first Messianic prophecy, foretelling the seed of the woman crushing the serpent', 'It describes the flood', 'It promises the land of Canaan', 'b', 'Genesis 3:15 is the first Messianic prophecy: "her seed...shall bruise thy head, and thou shalt bruise his heel."'),
('Genesis', 3, 'adults', 3, 'What specific curse was placed upon the ground because of Adam?', 'It would be flooded', 'It would be cursed and bring forth thorns and thistles', 'It would become desert', 'It would not grow trees', 'b', 'Cursed is the ground for thy sake; thorns also and thistles shall it bring forth (Genesis 3:17-18).'),
('Genesis', 3, 'adults', 4, 'What does the phrase "the eyes of them both were opened" in Genesis 3:7 refer to?', 'They gained physical sight', 'They became aware of their nakedness and experienced moral awareness', 'They could see spiritual beings', 'They could see the future', 'b', 'Their eyes were opened and they knew they were naked — they gained moral awareness of sin (Genesis 3:7).'),
('Genesis', 3, 'adults', 5, 'What reason does God give in Genesis 3:22 for expelling man from the garden?', 'Man was too sinful to remain', 'Lest man eat of the tree of life and live forever in a fallen state', 'The garden was no longer suitable', 'Man needed to learn to farm', 'b', 'Lest he put forth his hand, and take also of the tree of life, and eat, and live for ever (Genesis 3:22).'),
('Genesis', 3, 'adults', 6, 'What name did Adam give his wife, and what does it mean?', 'Sarah, meaning princess', 'Eve, because she was the mother of all living', 'Mary, meaning beloved', 'Hannah, meaning grace', 'b', 'Adam called his wife''s name Eve; because she was the mother of all living (Genesis 3:20).'),
('Genesis', 3, 'adults', 7, 'How did Adam respond when God confronted him about eating the fruit?', 'He confessed immediately', 'He blamed the woman God gave him', 'He denied eating it', 'He asked for forgiveness', 'b', 'Adam said, "The woman whom thou gavest to be with me, she gave me of the tree, and I did eat" (Genesis 3:12).'),
('Genesis', 3, 'adults', 8, 'What is the theological significance of God making coats of skins for Adam and Eve?', 'God wanted them to be warm', 'It foreshadows substitutionary atonement — an animal died to cover their sin', 'God was teaching them to sew', 'It was a punishment for their sin', 'b', 'God''s provision of animal skins required the death of an animal, foreshadowing the principle of blood atonement (Genesis 3:21).');

-- ═══ Genesis Chapter 4 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Genesis', 4, 'kids', 1, 'Who were Adam and Eve''s first two sons?', 'Jacob and Esau', 'Moses and Aaron', 'Cain and Abel', 'Shem and Ham', 'c', 'Eve bare Cain, and again bare his brother Abel (Genesis 4:1-2).'),
('Genesis', 4, 'kids', 2, 'What was Abel''s job?', 'A farmer', 'A builder', 'A shepherd', 'A fisherman', 'c', 'Abel was a keeper of sheep (Genesis 4:2).'),
('Genesis', 4, 'kids', 3, 'What terrible thing did Cain do to Abel?', 'He stole his sheep', 'He lied to him', 'He killed him', 'He sent him away', 'c', 'Cain rose up against Abel his brother, and slew him (Genesis 4:8).'),
-- Teens
('Genesis', 4, 'teens', 1, 'Why was God not pleased with Cain''s offering?', 'Cain brought too little', 'God did not have respect unto Cain and his offering, while Abel brought the firstlings of his flock', 'Cain''s offering was unclean', 'Cain forgot to pray first', 'b', 'The Lord had respect unto Abel and his offering, but unto Cain and his offering he had not respect (Genesis 4:4-5).'),
('Genesis', 4, 'teens', 2, 'What did God warn Cain about before the murder?', 'That Abel was stronger', 'That sin lieth at the door and desires to have him', 'That a flood would come', 'That he would be cursed to wander', 'b', 'God said, "Sin lieth at the door. And unto thee shall be his desire, and thou shalt rule over it" (Genesis 4:7).'),
('Genesis', 4, 'teens', 3, 'What was Cain''s punishment for killing Abel?', 'He was put to death', 'He was cursed from the earth and became a fugitive and vagabond', 'He was sent to prison', 'He lost all his crops forever', 'b', 'God said Cain would be a fugitive and a vagabond in the earth (Genesis 4:12).'),
('Genesis', 4, 'teens', 4, 'What did God put on Cain so no one would kill him?', 'A shield of protection', 'A mark', 'A helmet', 'A ring', 'b', 'The LORD set a mark upon Cain, lest any finding him should kill him (Genesis 4:15).'),
('Genesis', 4, 'teens', 5, 'Where did Cain go to live after leaving God''s presence?', 'The land of Canaan', 'The land of Nod', 'The land of Egypt', 'The land of Shinar', 'b', 'Cain went out from the presence of the LORD, and dwelt in the land of Nod, on the east of Eden (Genesis 4:16).'),
-- Adults
('Genesis', 4, 'adults', 1, 'What offering did Abel bring to the Lord?', 'Grain and herbs', 'The firstlings of his flock and the fat thereof', 'A burnt offering of doves', 'Wine and oil', 'b', 'Abel brought of the firstlings of his flock and of the fat thereof (Genesis 4:4).'),
('Genesis', 4, 'adults', 2, 'What famous question did Cain ask God in Genesis 4:9?', 'Why have you cursed me?', 'Where is my brother?', 'Am I my brother''s keeper?', 'What have I done wrong?', 'c', 'Cain said, "Am I my brother''s keeper?" (Genesis 4:9).'),
('Genesis', 4, 'adults', 3, 'What does God say Abel''s blood is doing in Genesis 4:10?', 'Staining the ground', 'Crying unto God from the ground', 'Polluting the rivers', 'Witnessing against Cain in heaven', 'b', 'The voice of thy brother''s blood crieth unto me from the ground (Genesis 4:10).'),
('Genesis', 4, 'adults', 4, 'What city did Cain build, and after whom was it named?', 'Babel, after himself', 'Enoch, after his son', 'Nod, after the land', 'Salem, after peace', 'b', 'Cain builded a city, and called the name of the city, after the name of his son, Enoch (Genesis 4:17).'),
('Genesis', 4, 'adults', 5, 'Who was Lamech in Cain''s line, and what is he notable for?', 'He was the first priest', 'He took two wives and boasted of killing a man', 'He built the tower of Babel', 'He was the first to offer sacrifice', 'b', 'Lamech took two wives and said he had slain a man to his wounding (Genesis 4:19, 23).'),
('Genesis', 4, 'adults', 6, 'Who was the father of all who handle the harp and organ?', 'Jabal', 'Jubal', 'Tubal-cain', 'Lamech', 'b', 'Jubal was the father of all such as handle the harp and organ (Genesis 4:21).'),
('Genesis', 4, 'adults', 7, 'Who was Tubal-cain, and what was he known for?', 'A mighty hunter', 'An instructor of every artificer in brass and iron', 'A builder of cities', 'A keeper of flocks', 'b', 'Tubal-cain was an instructor of every artificer in brass and iron (Genesis 4:22).'),
('Genesis', 4, 'adults', 8, 'What son was born to Adam and Eve to replace Abel?', 'Enoch', 'Jared', 'Seth', 'Enos', 'c', 'Eve bare a son and called his name Seth, saying God hath appointed me another seed instead of Abel (Genesis 4:25).');

-- ═══ Genesis Chapter 5 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Genesis', 5, 'kids', 1, 'Who lived the longest in the Bible at 969 years?', 'Noah', 'Adam', 'Methuselah', 'Enoch', 'c', 'Methuselah lived nine hundred sixty and nine years (Genesis 5:27).'),
('Genesis', 5, 'kids', 2, 'What happened to Enoch instead of dying?', 'He fell asleep', 'God took him', 'He became an angel', 'He sailed away', 'b', 'Enoch walked with God: and he was not; for God took him (Genesis 5:24).'),
('Genesis', 5, 'kids', 3, 'Who was Noah''s father?', 'Methuselah', 'Lamech', 'Enoch', 'Adam', 'b', 'Lamech begat a son and called his name Noah (Genesis 5:28-29).'),
-- Teens
('Genesis', 5, 'teens', 1, 'What unique phrase is used to describe Enoch''s relationship with God?', 'He prayed to God daily', 'He walked with God', 'He served God faithfully', 'He worshipped God alone', 'b', 'Enoch walked with God: and he was not; for God took him (Genesis 5:24).'),
('Genesis', 5, 'teens', 2, 'How old was Adam when he died?', 'Seven hundred years', 'Eight hundred and fifty years', 'Nine hundred and thirty years', 'One thousand years', 'c', 'All the days that Adam lived were nine hundred and thirty years: and he died (Genesis 5:5).'),
('Genesis', 5, 'teens', 3, 'What phrase is repeated throughout Genesis 5 about each patriarch?', '"And he was blessed"', '"And he died"', '"And he was faithful"', '"And God loved him"', 'b', 'The recurring phrase "and he died" emphasizes the reality of death after the fall.'),
('Genesis', 5, 'teens', 4, 'What does Lamech say Noah''s name means or relates to?', 'Rest and comfort from their work', 'Strength of God', 'Man of the water', 'Chosen by God', 'a', 'Lamech called him Noah, saying, "This same shall comfort us concerning our work and toil" (Genesis 5:29).'),
('Genesis', 5, 'teens', 5, 'How many sons of Noah are named in chapter 5?', 'One', 'Two', 'Three', 'Four', 'c', 'Noah begat Shem, Ham, and Japheth — three sons (Genesis 5:32).'),
-- Adults
('Genesis', 5, 'adults', 1, 'In what likeness did God make Adam according to Genesis 5:1?', 'In the likeness of the angels', 'In the likeness of God', 'In the likeness of heaven', 'In his own separate likeness', 'b', 'In the day that God created man, in the likeness of God made he him (Genesis 5:1).'),
('Genesis', 5, 'adults', 2, 'In whose likeness did Adam beget Seth?', 'In the likeness of God', 'In his own likeness, after his image', 'In the likeness of Abel', 'In the likeness of Eve', 'b', 'Adam begat a son in his own likeness, after his image, and called his name Seth (Genesis 5:3).'),
('Genesis', 5, 'adults', 3, 'How old was Enoch when God took him?', 'Three hundred years', 'Three hundred and sixty-five years', 'Four hundred years', 'Five hundred years', 'b', 'All the days of Enoch were three hundred sixty and five years (Genesis 5:23).'),
('Genesis', 5, 'adults', 4, 'What is notable about Enoch in the genealogy compared to every other patriarch?', 'He had the most children', 'He lived the shortest and never died', 'He was the firstborn', 'He was a priest', 'b', 'Unlike every other patriarch who "died," Enoch "was not; for God took him" (Genesis 5:24).'),
('Genesis', 5, 'adults', 5, 'How old was Noah when his three sons were born (approximately)?', 'Two hundred years old', 'Three hundred years old', 'Five hundred years old', 'Seven hundred years old', 'c', 'Noah was five hundred years old: and Noah begat Shem, Ham, and Japheth (Genesis 5:32).'),
('Genesis', 5, 'adults', 6, 'The genealogy in Genesis 5 traces the line from Adam to Noah through which son of Adam?', 'Cain', 'Abel', 'Seth', 'Enoch', 'c', 'The godly line is traced through Seth, not Cain (Genesis 5:3-32).'),
('Genesis', 5, 'adults', 7, 'What theological purpose does the Genesis 5 genealogy serve?', 'It shows that the earth is very old', 'It establishes the unbroken line from Adam to Noah and the reality of death', 'It proves that angels married humans', 'It records all the people who ever lived', 'b', 'The genealogy traces the covenant line from Adam to Noah, with "and he died" underscoring the consequence of the fall.'),
('Genesis', 5, 'adults', 8, 'How old was Methuselah when he died, and what is significant about the timing?', 'He died at 900, before the flood', 'He died at 969, the year of the flood', 'He died at 950, after the flood', 'He died at 777, a number of perfection', 'b', 'Methuselah died at 969 years old. Calculating from the genealogy, his death occurred in the year of the flood (Genesis 5:25-27).');

-- ═══════════════════════════════════════════
-- CHAPTERS 6 – 10
-- ═══════════════════════════════════════════

-- ═══ Genesis Chapter 6 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Genesis', 6, 'kids', 1, 'Who did God ask to build a big boat?', 'Adam', 'Moses', 'Noah', 'Abraham', 'c', 'God told Noah to build an ark (Genesis 6:13-14).'),
('Genesis', 6, 'kids', 2, 'Why did God want to send a flood?', 'Because it hadn''t rained in a long time', 'Because people were very wicked', 'Because the animals needed water', 'Because He wanted to fill the rivers', 'b', 'God saw that the wickedness of man was great in the earth (Genesis 6:5).'),
('Genesis', 6, 'kids', 3, 'What was the big boat called?', 'A ship', 'An ark', 'A raft', 'A canoe', 'b', 'God told Noah to make an ark of gopher wood (Genesis 6:14).'),
-- Teens
('Genesis', 6, 'teens', 1, 'What does Genesis 6:5 say about the state of mankind?', 'Every thought was sometimes evil', 'Every imagination of man''s heart was only evil continually', 'Most people were wicked but some were good', 'People had forgotten God''s name', 'b', 'Every imagination of the thoughts of his heart was only evil continually (Genesis 6:5).'),
('Genesis', 6, 'teens', 2, 'What does it mean that Noah "found grace in the eyes of the LORD"?', 'Noah earned God''s favor by his works', 'God chose to show unmerited favor to Noah', 'Noah discovered a secret about God', 'Noah prayed more than anyone else', 'b', 'Noah found grace in the eyes of the LORD — the first mention of grace in the Bible (Genesis 6:8).'),
('Genesis', 6, 'teens', 3, 'What kind of wood was the ark made from?', 'Cedar wood', 'Oak wood', 'Gopher wood', 'Pine wood', 'c', 'God said, "Make thee an ark of gopher wood" (Genesis 6:14).'),
('Genesis', 6, 'teens', 4, 'How many of each kind of animal was Noah told to bring on the ark?', 'One of each', 'Two of each', 'Five of each', 'Seven of each', 'b', 'Noah was to bring two of every sort into the ark, male and female (Genesis 6:19-20).'),
('Genesis', 6, 'teens', 5, 'How is Noah described in Genesis 6:9?', 'A mighty warrior', 'A just man and perfect in his generations who walked with God', 'A wise teacher', 'A wealthy farmer', 'b', 'Noah was a just man and perfect in his generations, and Noah walked with God (Genesis 6:9).'),
-- Adults
('Genesis', 6, 'adults', 1, 'What does Genesis 6:2 describe about the "sons of God"?', 'They worshipped idols', 'They took wives of the daughters of men', 'They built cities', 'They sacrificed to false gods', 'b', 'The sons of God saw the daughters of men that they were fair; and they took them wives (Genesis 6:2).'),
('Genesis', 6, 'adults', 2, 'What limit did God set on man''s days in Genesis 6:3?', 'One hundred years', 'One hundred and twenty years', 'Two hundred years', 'Seventy years', 'b', 'The LORD said, "My spirit shall not always strive with man...his days shall be an hundred and twenty years" (Genesis 6:3).'),
('Genesis', 6, 'adults', 3, 'Who are the "giants" (Nephilim) mentioned in Genesis 6:4?', 'Fallen angels who lived on earth', 'Mighty men of old, men of renown', 'Large animals before the flood', 'Descendants of Seth only', 'b', 'There were giants in the earth in those days...mighty men which were of old, men of renown (Genesis 6:4).'),
('Genesis', 6, 'adults', 4, 'What does Genesis 6:6 say about God''s emotional response to man''s wickedness?', 'God was angry and wrathful', 'It repented the LORD that he had made man, and it grieved him at his heart', 'God was indifferent to their sin', 'God laughed at their foolishness', 'b', 'It repented the LORD that he had made man on the earth, and it grieved him at his heart (Genesis 6:6).'),
('Genesis', 6, 'adults', 5, 'What were the dimensions of the ark in cubits?', '200 long, 30 wide, 20 high', '300 long, 50 wide, 30 high', '400 long, 60 wide, 40 high', '150 long, 25 wide, 15 high', 'b', 'The length 300 cubits, the breadth 50 cubits, and the height 30 cubits (Genesis 6:15).'),
('Genesis', 6, 'adults', 6, 'How many stories (levels) did the ark have?', 'One', 'Two', 'Three', 'Four', 'c', 'With lower, second, and third stories shalt thou make it (Genesis 6:16).'),
('Genesis', 6, 'adults', 7, 'What covenant did God establish with Noah before the flood?', 'A covenant of the rainbow', 'A covenant to bring Noah and his family safely into the ark', 'A covenant of circumcision', 'A covenant of sacrifice', 'b', 'God said, "With thee will I establish my covenant; and thou shalt come into the ark" (Genesis 6:18).'),
('Genesis', 6, 'adults', 8, 'What was Noah instructed to take on the ark besides animals?', 'Gold and silver', 'Seeds for planting', 'Food for his family and the animals', 'Tools and weapons', 'c', 'God said, "Take thou unto thee of all food that is eaten...for thee and for them" (Genesis 6:21).');

-- ═══ Genesis Chapter 7 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Genesis', 7, 'kids', 1, 'How many days and nights did it rain during the flood?', '7 days and nights', '20 days and nights', '40 days and nights', '100 days and nights', 'c', 'The rain was upon the earth forty days and forty nights (Genesis 7:12).'),
('Genesis', 7, 'kids', 2, 'How many people were saved on the ark?', 'Four', 'Eight', 'Twelve', 'Twenty', 'b', 'Noah, his wife, his three sons, and their three wives — eight people (Genesis 7:13).'),
('Genesis', 7, 'kids', 3, 'Who shut the door of the ark?', 'Noah', 'Noah''s sons', 'The angels', 'God (the LORD)', 'd', 'The LORD shut him in (Genesis 7:16).'),
-- Teens
('Genesis', 7, 'teens', 1, 'How many of the clean animals did Noah take on the ark?', 'Two of each', 'Seven of each', 'Five of each', 'Ten of each', 'b', 'Of every clean beast thou shalt take to thee by sevens, the male and his female (Genesis 7:2).'),
('Genesis', 7, 'teens', 2, 'How old was Noah when the flood began?', 'Four hundred years old', 'Five hundred years old', 'Six hundred years old', 'Seven hundred years old', 'c', 'Noah was six hundred years old when the flood of waters was upon the earth (Genesis 7:6).'),
('Genesis', 7, 'teens', 3, 'What happened after Noah entered the ark and before the rain started?', 'God waited 40 days', 'God waited 7 days', 'The ark floated immediately', 'An earthquake shook the land', 'b', 'After seven days the waters of the flood were upon the earth (Genesis 7:10).'),
('Genesis', 7, 'teens', 4, 'Besides rain, where else did the flood waters come from?', 'Melting ice from the mountains', 'The fountains of the great deep were broken up', 'Rivers overflowed their banks', 'The sea rose up', 'b', 'The fountains of the great deep broken up, and the windows of heaven were opened (Genesis 7:11).'),
('Genesis', 7, 'teens', 5, 'How high did the waters rise above the mountains?', 'Five cubits', 'Fifteen cubits', 'Thirty cubits', 'Fifty cubits', 'b', 'Fifteen cubits upward did the waters prevail; and the mountains were covered (Genesis 7:20).'),
-- Adults
('Genesis', 7, 'adults', 1, 'On what specific date did the flood begin according to Genesis 7:11?', 'The first day of the first month', 'The seventeenth day of the second month', 'The tenth day of the seventh month', 'The first day of the tenth month', 'b', 'In the second month, the seventeenth day of the month...were all the fountains of the great deep broken up (Genesis 7:11).'),
('Genesis', 7, 'adults', 2, 'What is the significance of God shutting the door of the ark in Genesis 7:16?', 'The door was too heavy for Noah', 'It symbolizes God''s sovereign protection and the closing of the opportunity for salvation', 'Noah forgot to close it', 'It was a test of faith', 'b', 'The LORD shut him in (Genesis 7:16) — God himself sealed the ark, indicating divine protection and judgment.'),
('Genesis', 7, 'adults', 3, 'Why were clean beasts taken by sevens and unclean by twos?', 'Clean beasts were smaller', 'Extra clean animals were needed for post-flood sacrifice', 'God favored clean animals', 'Unclean animals were more dangerous', 'b', 'The extra clean animals provided for sacrifice after the flood (Genesis 7:2; cf. 8:20).'),
('Genesis', 7, 'adults', 4, 'What phrase in Genesis 7:11 refers to subterranean water sources?', 'The rivers of the deep', 'The fountains of the great deep', 'The wells of the earth', 'The springs of the abyss', 'b', 'All the fountains of the great deep broken up (Genesis 7:11).'),
('Genesis', 7, 'adults', 5, 'How many total days did the waters prevail upon the earth?', 'Forty days', 'One hundred days', 'One hundred and fifty days', 'Three hundred and sixty-five days', 'c', 'The waters prevailed upon the earth an hundred and fifty days (Genesis 7:24).'),
('Genesis', 7, 'adults', 6, 'What is the theological significance of only eight people surviving the flood?', 'Eight was a lucky number', 'It demonstrates that salvation is for a remnant while judgment falls on the unrepentant', 'It was a coincidence', 'It fulfilled a prophecy by Enoch', 'b', 'Only eight souls were saved, illustrating the principle of a faithful remnant (Genesis 7:13; cf. 1 Peter 3:20).'),
('Genesis', 7, 'adults', 7, 'What does Genesis 7:16 say about the animals entering the ark?', 'Noah herded them in with great difficulty', 'They went in male and female as God had commanded Noah', 'They were carried by angels', 'They ran in from fear of the rain', 'b', 'They went in male and female of all flesh, as God had commanded him (Genesis 7:16).'),
('Genesis', 7, 'adults', 8, 'What specific phrase describes the totality of the destruction outside the ark?', 'Many were lost', 'All flesh died that moved upon the earth', 'Most creatures perished', 'The land was emptied', 'b', 'All flesh died that moved upon the earth, both of fowl, and of cattle, and of beast (Genesis 7:21).');

-- ═══ Genesis Chapter 8 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Genesis', 8, 'kids', 1, 'What bird did Noah send out first to check for dry land?', 'A dove', 'A raven', 'A sparrow', 'An eagle', 'b', 'Noah sent forth a raven, which went to and fro (Genesis 8:7).'),
('Genesis', 8, 'kids', 2, 'What did the dove bring back to the ark?', 'A flower', 'An olive leaf', 'A stick', 'A berry', 'b', 'The dove came back with an olive leaf pluckt off in her mouth (Genesis 8:11).'),
('Genesis', 8, 'kids', 3, 'What did Noah build after leaving the ark?', 'A house', 'An altar to God', 'A new boat', 'A garden', 'b', 'Noah builded an altar unto the LORD (Genesis 8:20).'),
-- Teens
('Genesis', 8, 'teens', 1, 'What mountains did the ark rest upon?', 'Mount Sinai', 'Mount Hermon', 'The mountains of Ararat', 'Mount Carmel', 'c', 'The ark rested upon the mountains of Ararat (Genesis 8:4).'),
('Genesis', 8, 'teens', 2, 'How many times did Noah send out the dove?', 'Once', 'Twice', 'Three times', 'Four times', 'c', 'Noah sent the dove three times: first it returned empty, then with an olive leaf, then it did not return (Genesis 8:8-12).'),
('Genesis', 8, 'teens', 3, 'What did Noah offer on the altar he built?', 'Grain and fruit', 'Burnt offerings of every clean beast and fowl', 'Prayers and songs', 'Incense and oil', 'b', 'Noah offered burnt offerings of every clean beast and every clean fowl on the altar (Genesis 8:20).'),
('Genesis', 8, 'teens', 4, 'What did God promise in His heart after smelling Noah''s offering?', 'He would destroy wickedness with fire next time', 'He would not again curse the ground for man''s sake or destroy every living thing', 'He would never allow sin again', 'He would make man perfect', 'b', 'The LORD said in his heart, I will not again curse the ground any more for man''s sake (Genesis 8:21).'),
('Genesis', 8, 'teens', 5, 'What cycle did God promise would never cease?', 'The cycle of life and death', 'Seedtime and harvest, cold and heat, summer and winter, day and night', 'The seasons of worship', 'The cycle of floods and droughts', 'b', 'While the earth remaineth, seedtime and harvest, and cold and heat, and summer and winter, and day and night shall not cease (Genesis 8:22).'),
-- Adults
('Genesis', 8, 'adults', 1, 'On what date did the ark come to rest on the mountains of Ararat?', 'The first day of the tenth month', 'The seventeenth day of the seventh month', 'The first day of the first month', 'The twenty-seventh day of the second month', 'b', 'In the seventh month, on the seventeenth day of the month, the ark rested upon the mountains of Ararat (Genesis 8:4).'),
('Genesis', 8, 'adults', 2, 'What did God cause to pass over the earth to help dry the waters?', 'A great heat', 'A wind', 'Fire from heaven', 'An earthquake', 'b', 'God made a wind to pass over the earth, and the waters assuaged (Genesis 8:1).'),
('Genesis', 8, 'adults', 3, 'How does the raven''s behavior differ from the dove''s on the first sending?', 'The raven came back immediately; the dove did not return', 'The raven went to and fro until waters dried; the dove returned finding no rest', 'Both returned immediately', 'The raven drowned; the dove flew far away', 'b', 'The raven went forth to and fro; the dove found no rest for the sole of her foot and returned (Genesis 8:7-9).'),
('Genesis', 8, 'adults', 4, 'What does God acknowledge about man''s heart in Genesis 8:21 even after the flood?', 'Man''s heart is now purified', 'The imagination of man''s heart is evil from his youth', 'Man will never sin again', 'Man has learned his lesson', 'b', 'The imagination of man''s heart is evil from his youth (Genesis 8:21).'),
('Genesis', 8, 'adults', 5, 'How long was Noah in the ark from the time the flood began to the time he exited?', 'About 150 days', 'About 265 days', 'About one solar year (approximately 370 days)', 'Exactly 40 days', 'c', 'Comparing Genesis 7:11 and 8:14, Noah was in the ark roughly one year and ten days.'),
('Genesis', 8, 'adults', 6, 'What did God "remember" in Genesis 8:1 that initiated the receding of waters?', 'His anger against sin', 'Noah, and every living thing in the ark', 'The garden of Eden', 'His promise to Adam', 'b', 'God remembered Noah, and every living thing, and all the cattle that was with him in the ark (Genesis 8:1).'),
('Genesis', 8, 'adults', 7, 'What is the theological significance of Noah''s altar and sacrifice after the flood?', 'It was merely a cultural tradition', 'It represents worship and thanksgiving, and prefigures the principle of substitutionary sacrifice', 'It was required to complete the flood narrative', 'It had no special meaning', 'b', 'Noah''s sacrifice of clean animals on an altar foreshadows the Levitical sacrificial system (Genesis 8:20).'),
('Genesis', 8, 'adults', 8, 'What command did God give Noah upon leaving the ark?', 'Build a city', 'Go forth and multiply upon the earth', 'Return to Eden', 'Divide the land among his sons', 'b', 'God said, "Go forth of the ark...bring forth every living thing...that they may breed abundantly" (Genesis 8:16-17).');

-- ═══ Genesis Chapter 9 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Genesis', 9, 'kids', 1, 'What sign did God put in the sky as a promise?', 'A star', 'A rainbow', 'A cloud', 'The sun', 'b', 'God set a rainbow in the cloud as a sign of His covenant (Genesis 9:13).'),
('Genesis', 9, 'kids', 2, 'What did God promise with the rainbow?', 'It would always be sunny', 'He would never flood the whole earth again', 'Animals would always be friendly', 'It would rain every day', 'b', 'God promised He would never again destroy all flesh with a flood (Genesis 9:15).'),
('Genesis', 9, 'kids', 3, 'What did Noah plant after the flood?', 'A flower garden', 'A vineyard', 'A wheat field', 'An orchard of fig trees', 'b', 'Noah began to be an husbandman, and he planted a vineyard (Genesis 9:20).'),
-- Teens
('Genesis', 9, 'teens', 1, 'What new permission did God give mankind regarding food after the flood?', 'They could eat only vegetables', 'They could now eat meat as well as plants', 'They could only eat fish', 'They could eat fruit from any tree', 'b', 'Every moving thing that liveth shall be meat for you; even as the green herb have I given you all things (Genesis 9:3).'),
('Genesis', 9, 'teens', 2, 'What restriction did God place on eating meat?', 'It must be cooked thoroughly', 'They must not eat the blood', 'It must be from clean animals only', 'It must be offered to God first', 'b', 'Flesh with the life thereof, which is the blood thereof, shall ye not eat (Genesis 9:4).'),
('Genesis', 9, 'teens', 3, 'What did God say about anyone who sheds man''s blood?', 'They will be forgiven', 'By man shall his blood be shed, for in the image of God made he man', 'They must flee to another land', 'They must offer a sacrifice', 'b', 'Whoso sheddeth man''s blood, by man shall his blood be shed: for in the image of God made he man (Genesis 9:6).'),
('Genesis', 9, 'teens', 4, 'Which of Noah''s sons saw his father''s nakedness?', 'Shem', 'Ham', 'Japheth', 'All three sons', 'b', 'Ham, the father of Canaan, saw the nakedness of his father and told his two brethren (Genesis 9:22).'),
('Genesis', 9, 'teens', 5, 'Who was cursed because of Ham''s disrespect?', 'Ham himself', 'Canaan, Ham''s son', 'All of Ham''s children', 'Noah', 'b', 'Noah said, "Cursed be Canaan; a servant of servants shall he be" (Genesis 9:25).'),
-- Adults
('Genesis', 9, 'adults', 1, 'With whom did God establish the Noahic covenant?', 'Only Noah and his sons', 'Noah, his descendants, and every living creature', 'Only mankind', 'Only the clean animals', 'b', 'God said, "I establish my covenant with you, and with your seed after you, and with every living creature" (Genesis 9:9-10).'),
('Genesis', 9, 'adults', 2, 'What makes the Noahic covenant unique among biblical covenants?', 'It requires circumcision', 'It is unconditional and universal, applying to all living creatures', 'It applies only to Israel', 'It was temporary', 'b', 'The Noahic covenant is unconditional — God promises never to destroy the earth by flood regardless of human behavior (Genesis 9:11).'),
('Genesis', 9, 'adults', 3, 'What does Genesis 9:6 establish as a foundational principle of justice?', 'An eye for an eye', 'Capital punishment for murder because man is made in God''s image', 'Forgiveness for all sins', 'Trial by jury', 'b', 'Whoso sheddeth man''s blood, by man shall his blood be shed: for in the image of God made he man (Genesis 9:6).'),
('Genesis', 9, 'adults', 4, 'How did Shem and Japheth cover their father''s nakedness?', 'They looked away and called for help', 'They walked backward with a garment so they would not see him', 'They sent Ham to cover him', 'They woke Noah up first', 'b', 'Shem and Japheth took a garment, laid it upon both their shoulders, and went backward, and covered their father (Genesis 9:23).'),
('Genesis', 9, 'adults', 5, 'What blessing did Noah pronounce on Shem?', 'Shem would be the greatest warrior', 'Blessed be the LORD God of Shem', 'Shem would inherit all the earth', 'Shem would never die', 'b', 'Noah said, "Blessed be the LORD God of Shem; and Canaan shall be his servant" (Genesis 9:26).'),
('Genesis', 9, 'adults', 6, 'What did Noah say about Japheth in his blessing?', 'Japheth would rule over Shem', 'God shall enlarge Japheth, and he shall dwell in the tents of Shem', 'Japheth would be a priest', 'Japheth would build great cities', 'b', 'God shall enlarge Japheth, and he shall dwell in the tents of Shem (Genesis 9:27).'),
('Genesis', 9, 'adults', 7, 'How old was Noah when he died?', 'Nine hundred years', 'Nine hundred and fifty years', 'Nine hundred and sixty-nine years', 'Eight hundred and fifty years', 'b', 'All the days of Noah were nine hundred and fifty years: and he died (Genesis 9:29).'),
('Genesis', 9, 'adults', 8, 'What is the theological significance of the prohibition against eating blood in Genesis 9:4?', 'It was merely a dietary health rule', 'Blood represents life, which belongs to God, foreshadowing the sacredness of blood atonement', 'It was a temporary cultural practice', 'God disliked the taste of blood', 'b', 'The prohibition against eating blood (Genesis 9:4) establishes the principle that the life is in the blood, foundational to later atonement theology (cf. Leviticus 17:11).');

-- ═══ Genesis Chapter 10 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Genesis', 10, 'kids', 1, 'How many sons did Noah have?', 'Two', 'Three', 'Four', 'Five', 'b', 'Noah had three sons: Shem, Ham, and Japheth (Genesis 10:1).'),
('Genesis', 10, 'kids', 2, 'Who was called a mighty hunter before the LORD?', 'Shem', 'Ham', 'Nimrod', 'Canaan', 'c', 'Nimrod was a mighty hunter before the LORD (Genesis 10:9).'),
('Genesis', 10, 'kids', 3, 'What does Genesis 10 tell us about Noah''s grandsons?', 'They all lived together', 'They became the nations of the earth', 'They built one big city', 'They stayed on the ark', 'b', 'By these were the nations divided in the earth after the flood (Genesis 10:32).'),
-- Teens
('Genesis', 10, 'teens', 1, 'Genesis 10 is commonly known as what?', 'The Book of Generations', 'The Table of Nations', 'The Family Tree', 'The List of Tribes', 'b', 'Genesis 10 is known as the Table of Nations — it lists the descendants of Noah''s sons and the nations they founded.'),
('Genesis', 10, 'teens', 2, 'Whose descendants include Nimrod?', 'Shem', 'Japheth', 'Ham', 'Canaan', 'c', 'Cush begat Nimrod — Cush was a son of Ham (Genesis 10:6, 8).'),
('Genesis', 10, 'teens', 3, 'What land did Nimrod begin his kingdom in?', 'Canaan', 'Egypt', 'Shinar (Babylonia)', 'Assyria', 'c', 'The beginning of his kingdom was Babel, and Erech, and Accad, and Calneh, in the land of Shinar (Genesis 10:10).'),
('Genesis', 10, 'teens', 4, 'Which of Noah''s sons is the ancestor of the Semitic peoples?', 'Ham', 'Japheth', 'Shem', 'Canaan', 'c', 'Shem is the ancestor of the Semitic peoples, including Abraham and the Israelites (Genesis 10:21-31).'),
('Genesis', 10, 'teens', 5, 'What great cities did Nimrod build or establish?', 'Jerusalem and Bethlehem', 'Babel, Erech, Accad, and Nineveh', 'Sodom and Gomorrah', 'Ur and Haran', 'b', 'Nimrod built Babel, Erech, Accad, Calneh in Shinar, and went to Assyria and built Nineveh (Genesis 10:10-11).'),
-- Adults
('Genesis', 10, 'adults', 1, 'From which son of Noah are the Japhethite peoples descended, and what regions did they spread to?', 'Ham — they spread to Africa', 'Japheth — they spread to the coastlands and isles of the Gentiles', 'Shem — they spread to Mesopotamia', 'Canaan — they spread to the Levant', 'b', 'By these were the isles of the Gentiles divided in their lands (Genesis 10:5) — Japheth''s descendants.'),
('Genesis', 10, 'adults', 2, 'Who was Eber, and why is he significant?', 'He was a son of Ham who settled Egypt', 'He was a descendant of Shem from whom the name "Hebrew" likely derives', 'He was a builder of Babel', 'He was a priest of the Most High God', 'b', 'Eber was a descendant of Shem (Genesis 10:21, 24). The name "Hebrew" is thought to derive from Eber.'),
('Genesis', 10, 'adults', 3, 'What does the phrase "a mighty hunter before the LORD" likely imply about Nimrod?', 'He was a godly man who hunted for food', 'He was a powerful ruler and conqueror in defiance of God', 'He hunted only with God''s permission', 'He was a priest who offered animal sacrifices', 'b', 'Nimrod was a mighty hunter before the LORD (Genesis 10:9) — traditionally understood as a powerful, possibly defiant ruler.'),
('Genesis', 10, 'adults', 4, 'Which peoples descended from Canaan according to Genesis 10?', 'The Egyptians and Ethiopians', 'The Jebusites, Amorites, Hivites, and other Canaanite nations', 'The Persians and Medes', 'The Philistines only', 'b', 'Canaan begat Sidon, Heth, the Jebusite, the Amorite, the Girgasite, the Hivite, etc. (Genesis 10:15-18).'),
('Genesis', 10, 'adults', 5, 'What does Genesis 10:25 say happened in the days of Peleg?', 'A great famine occurred', 'The earth was divided', 'A great earthquake struck', 'The tower of Babel was completed', 'b', 'Unto Eber were born two sons: the name of one was Peleg; for in his days was the earth divided (Genesis 10:25).'),
('Genesis', 10, 'adults', 6, 'From Ham''s son Mizraim, which nation descended?', 'Babylon', 'Assyria', 'Egypt', 'Persia', 'c', 'Mizraim is the Hebrew name for Egypt. Ham begat Mizraim (Genesis 10:6).'),
('Genesis', 10, 'adults', 7, 'How does Genesis 10 organize the nations?', 'By geographic location only', 'By their families, tongues, lands, and nations', 'By their occupations', 'Alphabetically', 'b', 'These are the families of the sons of Noah, after their generations, in their nations (Genesis 10:32).'),
('Genesis', 10, 'adults', 8, 'What is the theological purpose of the Table of Nations in Genesis 10?', 'It is merely a historical record', 'It shows God''s sovereignty over all nations and sets the stage for the Babel narrative and Abrahamic call', 'It proves the flood was local', 'It lists the enemies of Israel', 'b', 'The Table of Nations shows how all humanity descended from one family, setting the stage for Babel (ch. 11) and God''s call of Abraham (ch. 12).');

-- ═══════════════════════════════════════════
-- CHAPTERS 11 – 15
-- ═══════════════════════════════════════════

-- ═══ Genesis Chapter 11 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Genesis', 11, 'kids', 1, 'What did the people try to build that reached up to heaven?', 'A mountain', 'A tower', 'A ladder', 'A tall tree', 'b', 'They said, "Let us build us a city and a tower, whose top may reach unto heaven" (Genesis 11:4).'),
('Genesis', 11, 'kids', 2, 'What did God do to stop the people from building the tower?', 'He knocked it down', 'He confused their languages so they couldn''t understand each other', 'He sent a flood', 'He made them fall asleep', 'b', 'The LORD did confound the language of all the earth (Genesis 11:9).'),
('Genesis', 11, 'kids', 3, 'What was the name of the place where the tower was built?', 'Jerusalem', 'Babel', 'Eden', 'Bethlehem', 'b', 'Therefore is the name of it called Babel (Genesis 11:9).'),
-- Teens
('Genesis', 11, 'teens', 1, 'What was the whole earth like before the Tower of Babel?', 'Divided into many kingdoms', 'Of one language and one speech', 'Silent with no speech', 'Full of many languages already', 'b', 'The whole earth was of one language, and of one speech (Genesis 11:1).'),
('Genesis', 11, 'teens', 2, 'Why did the people want to build the tower?', 'To worship God at a high place', 'To make a name for themselves and avoid being scattered', 'To protect themselves from another flood', 'To see the stars more closely', 'b', 'They said, "Let us make us a name, lest we be scattered abroad upon the face of the whole earth" (Genesis 11:4).'),
('Genesis', 11, 'teens', 3, 'What material did they use to build the tower instead of stone?', 'Wood and leaves', 'Brick and slime (tar)', 'Clay and straw', 'Iron and bronze', 'b', 'They had brick for stone, and slime had they for morter (Genesis 11:3).'),
('Genesis', 11, 'teens', 4, 'Who was Abram''s father?', 'Nahor', 'Haran', 'Terah', 'Shem', 'c', 'Terah begat Abram, Nahor, and Haran (Genesis 11:26).'),
('Genesis', 11, 'teens', 5, 'Where did Terah originally take his family before settling in Haran?', 'He set out for the land of Canaan', 'He headed for Egypt', 'He traveled to Babylon', 'He went back to Ararat', 'a', 'They went forth to go into the land of Canaan; and they came unto Haran, and dwelt there (Genesis 11:31).'),
-- Adults
('Genesis', 11, 'adults', 1, 'What is the theological significance of God saying "let us go down" in Genesis 11:7?', 'God needed to travel to the tower', 'The plural "us" echoes Genesis 1:26 and suggests the divine plurality', 'God was speaking to angels only', 'It was a figure of speech', 'b', 'The LORD said, "Go to, let us go down" — the plural mirrors the creation account''s "let us" (Genesis 11:7; cf. 1:26).'),
('Genesis', 11, 'adults', 2, 'What does the name "Babel" mean?', 'Gate of God', 'Confusion, because the LORD did there confound the language', 'Great city', 'Tower of heaven', 'b', 'The name of it called Babel; because the LORD did there confound the language of all the earth (Genesis 11:9).'),
('Genesis', 11, 'adults', 3, 'What was God''s concern about humanity in Genesis 11:6?', 'They were too numerous', 'Nothing would be restrained from them if they remained unified in rebellion', 'They would destroy the earth', 'They were too sinful to continue', 'b', 'The LORD said, "Now nothing will be restrained from them, which they have imagined to do" (Genesis 11:6).'),
('Genesis', 11, 'adults', 4, 'The genealogy in Genesis 11:10-26 traces which lineage?', 'Ham to Nimrod', 'Japheth to the Greeks', 'Shem to Abram', 'Canaan to the Canaanites', 'c', 'The genealogy traces the line from Shem through Eber, Peleg, and others down to Terah and Abram (Genesis 11:10-26).'),
('Genesis', 11, 'adults', 5, 'What notable decline is observed in the lifespans recorded in Genesis 11?', 'They increase steadily', 'They decrease significantly from Shem (600) to Terah (205)', 'They remain constant', 'They alternate between long and short', 'b', 'Lifespans decline from Shem (600 years) progressively to Terah (205 years), showing the post-flood decrease.'),
('Genesis', 11, 'adults', 6, 'Who was Abram''s wife, and what problem is mentioned about her?', 'Hagar; she was a foreigner', 'Sarai; she was barren', 'Rebekah; she was blind', 'Milcah; she was elderly', 'b', 'Abram''s wife was Sarai, and she was barren; she had no child (Genesis 11:29-30).'),
('Genesis', 11, 'adults', 7, 'What happened to Abram''s brother Haran?', 'He went to Egypt', 'He died in Ur of the Chaldees before his father Terah', 'He became king of Babel', 'He was lost at sea', 'b', 'Haran died before his father Terah in the land of his nativity, in Ur of the Chaldees (Genesis 11:28).'),
('Genesis', 11, 'adults', 8, 'How does the Tower of Babel narrative contrast with God''s mandate in Genesis 9:1?', 'There is no contrast', 'God commanded mankind to fill the earth, but at Babel they refused to scatter', 'God commanded them to build cities', 'The tower was a form of worship', 'b', 'God said "be fruitful and multiply and fill the earth" (9:1), but at Babel they said "lest we be scattered" (11:4) — direct defiance.');

-- ═══ Genesis Chapter 12 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Genesis', 12, 'kids', 1, 'What did God tell Abram to do?', 'Build a tower', 'Leave his country and go to a new land', 'Stay home and be a farmer', 'Go back to the garden of Eden', 'b', 'God said, "Get thee out of thy country...unto a land that I will shew thee" (Genesis 12:1).'),
('Genesis', 12, 'kids', 2, 'What did God promise to make Abram into?', 'A rich farmer', 'A great nation', 'A mighty warrior', 'A wise teacher', 'b', 'God said, "I will make of thee a great nation" (Genesis 12:2).'),
('Genesis', 12, 'kids', 3, 'Who went with Abram on his journey?', 'His brother Haran', 'His wife Sarai and nephew Lot', 'His parents', 'Moses and Aaron', 'b', 'Abram took Sarai his wife, and Lot his brother''s son (Genesis 12:5).'),
-- Teens
('Genesis', 12, 'teens', 1, 'What three promises did God make to Abram in Genesis 12:2-3?', 'A big house, many servants, and long life', 'A great nation, a great name, and a blessing to all families of the earth', 'A rich kingdom, a palace, and many sons', 'Victory in battle, wisdom, and eternal life', 'b', 'God promised to make Abram a great nation, bless him and make his name great, and bless all families of the earth through him (Genesis 12:2-3).'),
('Genesis', 12, 'teens', 2, 'How old was Abram when he left Haran?', 'Fifty years old', 'Sixty-five years old', 'Seventy-five years old', 'Eighty-five years old', 'c', 'Abram was seventy and five years old when he departed out of Haran (Genesis 12:4).'),
('Genesis', 12, 'teens', 3, 'Where did Abram build his first altar in Canaan?', 'At Bethel', 'At the plain of Moreh in Shechem', 'At Hebron', 'At Beersheba', 'b', 'Abram passed through the land unto the place of Sichem, unto the plain of Moreh, and there he builded an altar (Genesis 12:6-7).'),
('Genesis', 12, 'teens', 4, 'Why did Abram go to Egypt?', 'God told him to go', 'There was a famine in the land', 'He wanted to trade goods', 'He was fleeing from enemies', 'b', 'There was a famine in the land: and Abram went down into Egypt to sojourn there (Genesis 12:10).'),
('Genesis', 12, 'teens', 5, 'What did Abram ask Sarai to say in Egypt?', 'That she was his mother', 'That she was his sister', 'That she was a servant', 'That she was a widow', 'b', 'Abram said, "Say, I pray thee, thou art my sister" (Genesis 12:13).'),
-- Adults
('Genesis', 12, 'adults', 1, 'What is the theological term for God''s promise to Abram in Genesis 12:1-3?', 'The Mosaic Covenant', 'The Abrahamic Covenant', 'The Noahic Covenant', 'The Davidic Covenant', 'b', 'God''s promises to Abram in Genesis 12:1-3 are the foundation of the Abrahamic Covenant.'),
('Genesis', 12, 'adults', 2, 'What does the phrase "I will bless them that bless thee, and curse him that curseth thee" establish?', 'A personal protection plan for Abram', 'God''s protective relationship with Abram and his descendants', 'A war command', 'A temporary promise', 'b', 'God established a principle of blessing or cursing nations based on their treatment of Abram''s line (Genesis 12:3).'),
('Genesis', 12, 'adults', 3, 'What phrase in Genesis 12:3 has universal Messianic implications?', '"I will make thy name great"', '"In thee shall all families of the earth be blessed"', '"I will make of thee a great nation"', '"I will bless them that bless thee"', 'b', '"In thee shall all families of the earth be blessed" points to the Messiah coming through Abram''s line (Genesis 12:3; cf. Galatians 3:8).'),
('Genesis', 12, 'adults', 4, 'What moral problem did Abram''s deception about Sarai in Egypt create?', 'He broke a commandment', 'He endangered Sarai''s virtue and showed lack of faith in God''s promise to protect him', 'He was punished by God immediately', 'He lost all his possessions', 'b', 'Abram''s half-truth endangered Sarai and showed a failure of faith in God''s protection (Genesis 12:11-13).'),
('Genesis', 12, 'adults', 5, 'What did Pharaoh do when he discovered the truth about Sarai?', 'He imprisoned Abram', 'He rebuked Abram and sent him away with his wife and possessions', 'He declared war on Abram', 'He asked Abram to stay', 'b', 'Pharaoh called Abram and said, "What is this thou hast done unto me?" and sent him away (Genesis 12:18-20).'),
('Genesis', 12, 'adults', 6, 'What plagues did God send upon Pharaoh''s house?', 'Boils and sores', 'Great plagues because of Sarai', 'Locusts and frogs', 'Darkness and death', 'b', 'The LORD plagued Pharaoh and his house with great plagues because of Sarai (Genesis 12:17).'),
('Genesis', 12, 'adults', 7, 'Who were the Canaanites mentioned as being in the land when Abram arrived?', 'Descendants of Shem', 'Descendants of Canaan, son of Ham', 'Descendants of Japheth', 'Descendants of Esau', 'b', 'The Canaanite was then in the land (Genesis 12:6) — descendants of Canaan, son of Ham.'),
('Genesis', 12, 'adults', 8, 'What did God specifically promise Abram at Shechem?', 'I will make you a king', 'Unto thy seed will I give this land', 'You will live forever', 'Your wife will bear a son this year', 'b', 'The LORD appeared unto Abram, and said, Unto thy seed will I give this land (Genesis 12:7).');

-- ═══ Genesis Chapter 13 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Genesis', 13, 'kids', 1, 'Why did Abram and Lot need to separate?', 'They didn''t like each other', 'Their herds were too large to share the same land', 'God told them to', 'Lot wanted to go home', 'b', 'The land was not able to bear them, that they might dwell together, for their substance was great (Genesis 13:6).'),
('Genesis', 13, 'kids', 2, 'Which direction did Lot choose to go?', 'To the mountains', 'Toward the plain of Jordan', 'To the desert', 'Back to Egypt', 'b', 'Lot chose him all the plain of Jordan (Genesis 13:11).'),
('Genesis', 13, 'kids', 3, 'What did God promise to give Abram?', 'A big house', 'All the land he could see', 'A hundred sheep', 'A golden crown', 'b', 'God said, "All the land which thou seest, to thee will I give it" (Genesis 13:15).'),
-- Teens
('Genesis', 13, 'teens', 1, 'What was the conflict between Abram''s and Lot''s herdsmen about?', 'Water rights', 'The land could not support both of their large flocks', 'Stolen animals', 'Border disputes', 'b', 'There was strife between the herdmen because the land was not able to bear them both (Genesis 13:6-7).'),
('Genesis', 13, 'teens', 2, 'What generous offer did Abram make to Lot?', 'He offered Lot money to leave', 'He let Lot choose which land he wanted first', 'He gave Lot half his flock', 'He built Lot a new home', 'b', 'Abram said, "If thou wilt take the left hand, then I will go to the right" — he gave Lot first choice (Genesis 13:9).'),
('Genesis', 13, 'teens', 3, 'What was the plain of Jordan compared to in Genesis 13:10?', 'The desert of Arabia', 'The garden of the LORD and the land of Egypt', 'The mountains of Ararat', 'The forests of Lebanon', 'b', 'The plain of Jordan was well watered every where...as the garden of the LORD, like the land of Egypt (Genesis 13:10).'),
('Genesis', 13, 'teens', 4, 'Near what wicked city did Lot choose to live?', 'Babel', 'Nineveh', 'Sodom', 'Jericho', 'c', 'Lot dwelled in the cities of the plain, and pitched his tent toward Sodom (Genesis 13:12).'),
('Genesis', 13, 'teens', 5, 'What did God tell Abram to do to claim the land?', 'Build a wall around it', 'Walk through the length and breadth of it', 'Plant trees on it', 'Write his name on stones', 'b', 'God said, "Arise, walk through the land in the length of it and in the breadth of it; for I will give it unto thee" (Genesis 13:17).'),
-- Adults
('Genesis', 13, 'adults', 1, 'What does Genesis 13:13 reveal about the men of Sodom?', 'They were wealthy traders', 'They were wicked and sinners before the LORD exceedingly', 'They were peaceful farmers', 'They worshipped the true God', 'b', 'The men of Sodom were wicked and sinners before the LORD exceedingly (Genesis 13:13).'),
('Genesis', 13, 'adults', 2, 'How did God describe the number of Abram''s future descendants?', 'As many as the fish in the sea', 'As the dust of the earth — innumerable', 'As many as the trees in the forest', 'As the rivers flowing to the sea', 'b', 'God said, "I will make thy seed as the dust of the earth" (Genesis 13:16).'),
('Genesis', 13, 'adults', 3, 'Where did Abram settle after separating from Lot?', 'In Shechem', 'In the plain of Mamre in Hebron', 'In Bethel', 'In Beersheba', 'b', 'Abram dwelled in the plain of Mamre, which is in Hebron, and built there an altar unto the LORD (Genesis 13:18).'),
('Genesis', 13, 'adults', 4, 'What character flaw does Lot''s choice of the well-watered plain reveal?', 'Cowardice', 'He chose based on outward appearance and material gain rather than spiritual wisdom', 'Laziness', 'Hostility toward Abram', 'b', 'Lot chose based on what looked good — the well-watered plain — without considering the wickedness of Sodom (Genesis 13:10-13).'),
('Genesis', 13, 'adults', 5, 'In what four directions did God tell Abram to look to see the promised land?', 'East, west, north, south', 'Northward, southward, eastward, westward', 'Up, down, left, right', 'Forward, backward, left, right', 'b', 'God said, "Lift up thine eyes, and look from the place where thou art northward, and southward, and eastward, and westward" (Genesis 13:14).'),
('Genesis', 13, 'adults', 6, 'What was the time frame of God''s land promise to Abram?', 'For one hundred years', 'For ever', 'Until the coming of the Messiah', 'For three generations', 'b', 'God said, "To thee will I give it, and to thy seed for ever" (Genesis 13:15).'),
('Genesis', 13, 'adults', 7, 'What does Abram''s willingness to let Lot choose first demonstrate?', 'Indifference to the land', 'Faith that God would provide regardless of Lot''s choice', 'Weakness in negotiation', 'Desire to avoid conflict at any cost', 'b', 'Abram''s generosity shows trust in God''s promise — he didn''t need to grasp for the best portion (Genesis 13:8-9).'),
('Genesis', 13, 'adults', 8, 'What act of worship did Abram perform at Hebron?', 'He offered a burnt offering of sheep', 'He built an altar unto the LORD', 'He planted a vineyard', 'He erected a stone pillar', 'b', 'Abram came and dwelt in the plain of Mamre, in Hebron, and built there an altar unto the LORD (Genesis 13:18).');

-- ═══ Genesis Chapter 14 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Genesis', 14, 'kids', 1, 'What happened to Lot in this chapter?', 'He got lost', 'He was captured in a war', 'He built a new house', 'He found a treasure', 'b', 'They took Lot, Abram''s brother''s son, who dwelt in Sodom, and his goods (Genesis 14:12).'),
('Genesis', 14, 'kids', 2, 'What did Abram do when he heard Lot was captured?', 'He cried for help', 'He gathered his men and rescued Lot', 'He sent a letter', 'He waited for God to help', 'b', 'When Abram heard his brother was taken captive, he armed his trained servants and pursued them (Genesis 14:14).'),
('Genesis', 14, 'kids', 3, 'Who blessed Abram after the battle?', 'Pharaoh', 'Melchizedek, king of Salem', 'The king of Sodom', 'An angel', 'b', 'Melchizedek king of Salem brought forth bread and wine and blessed Abram (Genesis 14:18-19).'),
-- Teens
('Genesis', 14, 'teens', 1, 'How many trained servants did Abram arm to rescue Lot?', 'One hundred', 'Two hundred and eighteen', 'Three hundred and eighteen', 'Five hundred', 'c', 'Abram armed his trained servants, born in his own house, three hundred and eighteen (Genesis 14:14).'),
('Genesis', 14, 'teens', 2, 'Who was Melchizedek?', 'A warrior from Egypt', 'King of Salem and priest of the most high God', 'One of Lot''s friends', 'A prophet from Babylon', 'b', 'Melchizedek king of Salem brought forth bread and wine: and he was the priest of the most high God (Genesis 14:18).'),
('Genesis', 14, 'teens', 3, 'What did Abram give to Melchizedek?', 'A gold ring', 'Tithes of all (a tenth of everything)', 'Fifty sheep', 'His best servants', 'b', 'Abram gave him tithes of all (Genesis 14:20).'),
('Genesis', 14, 'teens', 4, 'What did the king of Sodom offer Abram after the battle?', 'His daughter in marriage', 'The goods and spoils of war', 'A treaty of peace', 'Land in Sodom', 'b', 'The king of Sodom said to Abram, "Give me the persons, and take the goods to thyself" (Genesis 14:21).'),
('Genesis', 14, 'teens', 5, 'Why did Abram refuse the king of Sodom''s offer?', 'He already had enough wealth', 'So the king could not say he had made Abram rich', 'He didn''t trust the king', 'God told him not to accept', 'b', 'Abram said, "Lest thou shouldest say, I have made Abram rich" (Genesis 14:23).'),
-- Adults
('Genesis', 14, 'adults', 1, 'Which king led the coalition of four kings against the five kings of the Jordan plain?', 'Melchizedek of Salem', 'Chedorlaomer king of Elam', 'Bera king of Sodom', 'Nimrod of Shinar', 'b', 'The four kings made war with the five kings, with Chedorlaomer as the dominant king (Genesis 14:1-4).'),
('Genesis', 14, 'adults', 2, 'How long had the five kings served Chedorlaomer before rebelling?', 'Five years', 'Ten years', 'Twelve years, and rebelled in the thirteenth', 'Twenty years', 'c', 'Twelve years they served Chedorlaomer, and in the thirteenth year they rebelled (Genesis 14:4).'),
('Genesis', 14, 'adults', 3, 'What geographical feature did the kings of Sodom and Gomorrah fall into during battle?', 'A river', 'Slimepits (tar pits)', 'A deep valley', 'A lake', 'b', 'The vale of Siddim was full of slimepits; and the kings of Sodom and Gomorrah fell there (Genesis 14:10).'),
('Genesis', 14, 'adults', 4, 'What is the theological significance of Melchizedek being both king and priest?', 'He was simply a local ruler with religious duties', 'He is a type of Christ who is both King and Priest, as referenced in Psalm 110 and Hebrews 7', 'He established the Levitical priesthood', 'He was an angel in disguise', 'b', 'Melchizedek as king-priest prefigures Christ (Genesis 14:18; cf. Psalm 110:4, Hebrews 7:1-3).'),
('Genesis', 14, 'adults', 5, 'What does "Salem" mean, and what city is it believed to be?', 'Victory — it is believed to be Babylon', 'Peace — it is believed to be Jerusalem', 'Strength — it is believed to be Samaria', 'Holy — it is believed to be Hebron', 'b', 'Salem means "peace" and is traditionally identified with Jerusalem (Genesis 14:18; cf. Psalm 76:2).'),
('Genesis', 14, 'adults', 6, 'What oath did Abram swear to the king of Sodom?', 'He swore by his own name', 'He lifted his hand unto the LORD, the most high God, that he would take nothing', 'He swore by the stars of heaven', 'He made no oath', 'b', 'Abram said, "I have lift up mine hand unto the LORD, the most high God...that I will not take any thing" (Genesis 14:22-23).'),
('Genesis', 14, 'adults', 7, 'What does Abram''s tithing to Melchizedek establish?', 'That taxes must be paid to kings', 'The principle of tithing predates the Mosaic Law', 'That Abram was Melchizedek''s servant', 'A military alliance between them', 'b', 'Abram''s tithe to Melchizedek shows the practice of giving a tenth existed before the Law of Moses (Genesis 14:20).'),
('Genesis', 14, 'adults', 8, 'Who did Abram say could take their portion of the spoils?', 'His wife Sarai', 'The young men and his allies Aner, Eshcol, and Mamre', 'Melchizedek and his servants', 'Lot and his family', 'b', 'Abram said, "Save only that which the young men have eaten, and the portion of the men which went with me, Aner, Eshcol, and Mamre" (Genesis 14:24).');

-- ═══ Genesis Chapter 15 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Genesis', 15, 'kids', 1, 'What did God tell Abram to count?', 'The grains of sand', 'The stars in the sky', 'The fish in the sea', 'The trees in the forest', 'b', 'God said, "Look now toward heaven, and tell the stars...so shall thy seed be" (Genesis 15:5).'),
('Genesis', 15, 'kids', 2, 'What did God promise Abram he would have?', 'A big house', 'More children than he could count', 'A golden throne', 'A hundred camels', 'b', 'God promised Abram''s descendants would be as numerous as the stars (Genesis 15:5).'),
('Genesis', 15, 'kids', 3, 'What did God say He was to Abram?', 'His king', 'His shield and great reward', 'His teacher', 'His brother', 'b', 'God said, "I am thy shield, and thy exceeding great reward" (Genesis 15:1).'),
-- Teens
('Genesis', 15, 'teens', 1, 'What was Abram''s concern in this chapter?', 'He was afraid of his enemies', 'He had no children, and his servant Eliezer would inherit', 'He was running out of food', 'He wanted to return to Haran', 'b', 'Abram said, "I go childless, and the steward of my house is this Eliezer of Damascus" (Genesis 15:2).'),
('Genesis', 15, 'teens', 2, 'What did Abram do when God promised him descendants as numerous as the stars?', 'He laughed', 'He believed in the LORD', 'He asked for proof', 'He was afraid', 'b', 'Abram believed in the LORD; and he counted it to him for righteousness (Genesis 15:6).'),
('Genesis', 15, 'teens', 3, 'How did God count Abram''s faith?', 'As obedience', 'As righteousness', 'As wisdom', 'As courage', 'b', 'He believed in the LORD; and he counted it to him for righteousness (Genesis 15:6).'),
('Genesis', 15, 'teens', 4, 'What did God tell Abram would happen to his descendants before they inherited the land?', 'They would wander the desert for 40 years', 'They would be strangers and servants in a land not theirs for 400 years', 'They would conquer Canaan immediately', 'They would live in peace for 100 years', 'b', 'God said, "Thy seed shall be a stranger in a land that is not theirs, and shall serve them...four hundred years" (Genesis 15:13).'),
('Genesis', 15, 'teens', 5, 'What strange vision did Abram see during the covenant ceremony?', 'A rainbow in the clouds', 'A smoking furnace and a burning lamp passing between the pieces', 'A pillar of fire', 'An angel with a sword', 'b', 'A smoking furnace, and a burning lamp passed between those pieces (Genesis 15:17).'),
-- Adults
('Genesis', 15, 'adults', 1, 'What key theological doctrine is established by Genesis 15:6?', 'Salvation by works', 'Justification by faith — Abram believed God and it was counted as righteousness', 'The necessity of circumcision', 'The importance of sacrifice', 'b', 'Genesis 15:6 establishes justification by faith, cited by Paul in Romans 4:3 and Galatians 3:6.'),
('Genesis', 15, 'adults', 2, 'What animals did God instruct Abram to bring for the covenant ceremony?', 'Two lambs and a dove', 'A heifer, a she goat, a ram (each three years old), a turtledove, and a young pigeon', 'A bull and seven lambs', 'Two goats and two pigeons', 'b', 'God said, "Take me an heifer of three years old, and a she goat of three years old, and a ram of three years old, and a turtledove, and a young pigeon" (Genesis 15:9).'),
('Genesis', 15, 'adults', 3, 'What did Abram do with the animals?', 'He burned them as a sacrifice', 'He divided them in the midst and laid each piece opposite the other', 'He released them into the field', 'He kept them as a flock', 'b', 'He took all these and divided them in the midst, and laid each piece one against another; but the birds divided he not (Genesis 15:10).'),
('Genesis', 15, 'adults', 4, 'What is the significance of God alone passing between the pieces in Genesis 15:17?', 'It was a standard ancient practice with no special meaning', 'It shows the covenant is unconditional — God alone binds Himself, not requiring Abram''s performance', 'It means Abram failed the test', 'It was a vision with no real meaning', 'b', 'In ancient covenant ritual, both parties walked between pieces. God alone passing through indicates an unconditional, one-sided covenant (Genesis 15:17).'),
('Genesis', 15, 'adults', 5, 'What did God prophesy about the nation that would enslave Abram''s descendants?', 'They would be destroyed by famine', 'God would judge that nation, and Abram''s seed would come out with great substance', 'They would become allies of Israel', 'They would convert to worship God', 'b', 'That nation, whom they shall serve, will I judge: and afterward shall they come out with great substance (Genesis 15:14).'),
('Genesis', 15, 'adults', 6, 'What reason does God give for the delay in giving the land to Abram''s seed?', 'The land was not yet fertile', 'The iniquity of the Amorites is not yet full', 'Abram''s family was not large enough', 'The Canaanites were too strong', 'b', 'The iniquity of the Amorites is not yet full (Genesis 15:16) — God delays judgment until sin reaches its fullness.'),
('Genesis', 15, 'adults', 7, 'What fell upon Abram as the sun was going down?', 'A gentle breeze', 'A deep sleep and a horror of great darkness', 'A bright light', 'Rain and thunder', 'b', 'When the sun was going down, a deep sleep fell upon Abram; and, lo, an horror of great darkness fell upon him (Genesis 15:12).'),
('Genesis', 15, 'adults', 8, 'What geographic boundaries did God define for the promised land in Genesis 15:18?', 'From Dan to Beersheba', 'From the river of Egypt unto the great river Euphrates', 'From the Mediterranean to the Jordan', 'From Mount Sinai to Mount Hermon', 'b', 'God said, "Unto thy seed have I given this land, from the river of Egypt unto the great river, the river Euphrates" (Genesis 15:18).');

-- ═══════════════════════════════════════════
-- CHAPTERS 16 – 20
-- ═══════════════════════════════════════════

-- ═══ Genesis Chapter 16 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Genesis', 16, 'kids', 1, 'Who was Sarai''s servant?', 'Rebekah', 'Hagar', 'Leah', 'Rachel', 'b', 'Sarai had an handmaid, an Egyptian, whose name was Hagar (Genesis 16:1).'),
('Genesis', 16, 'kids', 2, 'What was the name of Hagar''s son?', 'Isaac', 'Esau', 'Ishmael', 'Jacob', 'c', 'The angel of the LORD said, "Thou shalt call his name Ishmael" (Genesis 16:11).'),
('Genesis', 16, 'kids', 3, 'Where did the angel find Hagar when she ran away?', 'In the desert', 'By a fountain of water in the wilderness', 'On a mountain', 'In a city', 'b', 'The angel of the LORD found her by a fountain of water in the wilderness (Genesis 16:7).'),
-- Teens
('Genesis', 16, 'teens', 1, 'Why did Sarai give Hagar to Abram?', 'Hagar wanted to marry Abram', 'Sarai was barren and hoped to have children through Hagar', 'God commanded her to', 'Abram requested another wife', 'b', 'Sarai said, "The LORD hath restrained me from bearing: I pray thee, go in unto my maid; it may be that I may obtain children by her" (Genesis 16:2).'),
('Genesis', 16, 'teens', 2, 'What happened between Sarai and Hagar after Hagar became pregnant?', 'They became best friends', 'Hagar despised Sarai, and Sarai dealt harshly with her', 'Hagar left peacefully', 'Sarai was happy for Hagar', 'b', 'When Hagar saw she had conceived, her mistress was despised in her eyes, and Sarai dealt hardly with her (Genesis 16:4-6).'),
('Genesis', 16, 'teens', 3, 'What does the name Ishmael mean?', 'God provides', 'God hears', 'God protects', 'God blesses', 'b', 'Ishmael means "God shall hear" — because the LORD hath heard thy affliction (Genesis 16:11).'),
('Genesis', 16, 'teens', 4, 'What kind of man did the angel say Ishmael would be?', 'A peaceful shepherd', 'A wild man, his hand against every man', 'A great priest', 'A wealthy merchant', 'b', 'He will be a wild man; his hand will be against every man, and every man''s hand against him (Genesis 16:12).'),
('Genesis', 16, 'teens', 5, 'What did Hagar call the LORD who spoke to her?', 'El Shaddai', 'El Elyon', 'Thou God seest me (Beer-lahai-roi)', 'Jehovah Jireh', 'c', 'She called the name of the LORD that spake unto her, Thou God seest me (Genesis 16:13).'),
-- Adults
('Genesis', 16, 'adults', 1, 'What does Sarai''s plan to use Hagar as a surrogate reflect about her faith?', 'Complete trust in God', 'An attempt to fulfill God''s promise through human means rather than waiting on God', 'Obedience to God''s command', 'Cultural irrelevance', 'b', 'Sarai''s scheme reflects impatience with God''s timing and an attempt to fulfill the promise through human effort (Genesis 16:1-2).'),
('Genesis', 16, 'adults', 2, 'Who is the "angel of the LORD" that appears to Hagar, and why is this significant?', 'An ordinary angel', 'This is the first appearance of the angel of the LORD in Scripture, often understood as a theophany', 'A human messenger', 'The archangel Michael', 'b', 'Genesis 16:7 is the first occurrence of "the angel of the LORD" in the Bible, a figure many scholars identify as a pre-incarnate appearance of Christ.'),
('Genesis', 16, 'adults', 3, 'What did the angel tell Hagar to do?', 'Keep running to Egypt', 'Return to her mistress and submit herself', 'Go to a new land', 'Wait by the well until Abram came', 'b', 'The angel said, "Return to thy mistress, and submit thyself under her hands" (Genesis 16:9).'),
('Genesis', 16, 'adults', 4, 'What promise did the angel make about Hagar''s descendants?', 'They would be few but powerful', 'They would be multiplied exceedingly so they cannot be numbered', 'They would inherit Canaan', 'They would return to Egypt', 'b', 'The angel said, "I will multiply thy seed exceedingly, that it shall not be numbered for multitude" (Genesis 16:10).'),
('Genesis', 16, 'adults', 5, 'What does the name Beer-lahai-roi mean?', 'The well of the living God', 'The well of him that liveth and seeth me', 'The well of salvation', 'The well of tears', 'b', 'The well was called Beer-lahai-roi — "the well of him that liveth and seeth me" (Genesis 16:14).'),
('Genesis', 16, 'adults', 6, 'How old was Abram when Ishmael was born?', 'Seventy-five years old', 'Eighty years old', 'Eighty-six years old', 'Ninety years old', 'c', 'Abram was fourscore and six years old, when Hagar bare Ishmael (Genesis 16:16).'),
('Genesis', 16, 'adults', 7, 'What does Genesis 16:12 prophesy about Ishmael''s dwelling?', 'He would live in Egypt', 'He shall dwell in the presence of all his brethren', 'He would settle in Canaan', 'He would live alone in the desert', 'b', 'He shall dwell in the presence of all his brethren (Genesis 16:12).'),
('Genesis', 16, 'adults', 8, 'How does Hagar''s experience at the well foreshadow themes in Scripture?', 'It has no broader significance', 'God sees and hears the afflicted, a theme echoed in the Exodus and Psalms', 'It teaches about water purification', 'It only applies to Hagar''s situation', 'b', 'Hagar''s naming of God as "the God who sees me" establishes the theme that God sees and hears the oppressed (Genesis 16:13).');

-- ═══ Genesis Chapter 17 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Genesis', 17, 'kids', 1, 'What new name did God give Abram?', 'Israel', 'Abraham', 'Moses', 'David', 'b', 'God said, "Thy name shall be Abraham; for a father of many nations have I made thee" (Genesis 17:5).'),
('Genesis', 17, 'kids', 2, 'What new name did God give Sarai?', 'Ruth', 'Sarah', 'Hannah', 'Miriam', 'b', 'God said, "Thou shalt not call her name Sarai, but Sarah shall her name be" (Genesis 17:15).'),
('Genesis', 17, 'kids', 3, 'What son did God promise Abraham and Sarah would have?', 'Ishmael', 'Isaac', 'Jacob', 'Joseph', 'b', 'God said, "Sarah thy wife shall bear thee a son indeed; and thou shalt call his name Isaac" (Genesis 17:19).'),
-- Teens
('Genesis', 17, 'teens', 1, 'What does the name Abraham mean?', 'Mighty warrior', 'Father of many nations', 'Servant of God', 'Friend of God', 'b', 'God changed his name to Abraham, meaning "father of many nations" (Genesis 17:5).'),
('Genesis', 17, 'teens', 2, 'What sign of the covenant did God institute in this chapter?', 'The rainbow', 'Circumcision', 'Animal sacrifice', 'The Sabbath', 'b', 'God said, "Every man child among you shall be circumcised...it shall be a token of the covenant" (Genesis 17:10-11).'),
('Genesis', 17, 'teens', 3, 'At what age were males to be circumcised?', 'At birth', 'Eight days old', 'One year old', 'Thirteen years old', 'b', 'He that is eight days old shall be circumcised among you (Genesis 17:12).'),
('Genesis', 17, 'teens', 4, 'How did Abraham react when God said Sarah would have a son?', 'He praised God immediately', 'He fell on his face and laughed', 'He was afraid', 'He said nothing', 'b', 'Abraham fell upon his face, and laughed, and said, "Shall a child be born unto him that is an hundred years old?" (Genesis 17:17).'),
('Genesis', 17, 'teens', 5, 'How old was Abraham when he was circumcised?', 'Seventy-five years old', 'Eighty-six years old', 'Ninety-nine years old', 'One hundred years old', 'c', 'Abraham was ninety years old and nine, when he was circumcised (Genesis 17:24).'),
-- Adults
('Genesis', 17, 'adults', 1, 'By what name does God reveal Himself to Abraham in Genesis 17:1?', 'Yahweh', 'El Elyon', 'El Shaddai (God Almighty)', 'Adonai', 'c', 'The LORD appeared to Abram, and said, "I am the Almighty God (El Shaddai)" (Genesis 17:1).'),
('Genesis', 17, 'adults', 2, 'What command did God give Abraham along with the name El Shaddai?', 'Build an altar', 'Walk before me, and be thou perfect', 'Leave this land', 'Offer a sacrifice', 'b', 'God said, "Walk before me, and be thou perfect" (Genesis 17:1).'),
('Genesis', 17, 'adults', 3, 'What would be the penalty for an uncircumcised male in Israel?', 'He would pay a fine', 'That soul shall be cut off from his people for breaking the covenant', 'He would be exiled for a year', 'He would offer extra sacrifices', 'b', 'The uncircumcised man child whose flesh is not circumcised, that soul shall be cut off from his people; he hath broken my covenant (Genesis 17:14).'),
('Genesis', 17, 'adults', 4, 'What did God promise specifically regarding Ishmael in response to Abraham''s plea?', 'Ishmael would inherit the covenant', 'God would bless Ishmael, make him fruitful, and make him the father of twelve princes', 'Ishmael would be sent away immediately', 'Ishmael would become a priest', 'b', 'God said, "I have blessed him, and will make him fruitful...twelve princes shall he beget" (Genesis 17:20).'),
('Genesis', 17, 'adults', 5, 'With whom did God say He would establish His covenant — Isaac or Ishmael?', 'Ishmael, as the firstborn', 'Isaac, whom Sarah would bear', 'Both equally', 'Neither — with Abraham alone', 'b', 'God said, "My covenant will I establish with Isaac, which Sarah shall bear unto thee" (Genesis 17:21).'),
('Genesis', 17, 'adults', 6, 'What does the name Isaac mean, and why?', 'Promise — because God promised him', 'Laughter — because both Abraham and Sarah laughed', 'Blessing — because he was a blessed child', 'Miracle — because his birth was miraculous', 'b', 'Isaac means "he laughs" — Abraham laughed (17:17) and Sarah later laughed (18:12) at the promise.'),
('Genesis', 17, 'adults', 7, 'How old was Ishmael when he was circumcised?', 'Eight days old', 'Ten years old', 'Thirteen years old', 'Twenty years old', 'c', 'Ishmael his son was thirteen years old, when he was circumcised (Genesis 17:25).'),
('Genesis', 17, 'adults', 8, 'What is the theological significance of circumcision as a covenant sign?', 'It was merely a health practice', 'It was an outward sign of an inward covenant relationship, applied to the organ of reproduction to symbolize the covenant passing through generations', 'It was a punishment for sin', 'It had no deeper meaning', 'b', 'Circumcision as a sign in the flesh of the reproductive organ symbolizes the covenant being passed through Abraham''s seed (Genesis 17:11).');

-- ═══ Genesis Chapter 18 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Genesis', 18, 'kids', 1, 'How many visitors came to see Abraham at his tent?', 'One', 'Two', 'Three', 'Four', 'c', 'The LORD appeared unto him...and, lo, three men stood by him (Genesis 18:1-2).'),
('Genesis', 18, 'kids', 2, 'What did Sarah do when she heard she would have a baby?', 'She cried', 'She laughed', 'She danced', 'She sang', 'b', 'Sarah laughed within herself (Genesis 18:12).'),
('Genesis', 18, 'kids', 3, 'What famous question did God ask about Sarah''s laughter?', 'Why are you afraid?', 'Is any thing too hard for the LORD?', 'Do you not believe?', 'Why did you laugh?', 'b', 'The LORD said, "Is any thing too hard for the LORD?" (Genesis 18:14).'),
-- Teens
('Genesis', 18, 'teens', 1, 'Where did the three visitors appear to Abraham?', 'At the well of Beersheba', 'By the oaks of Mamre', 'At the gate of a city', 'On Mount Moriah', 'b', 'The LORD appeared unto him in the plains of Mamre; and he sat in the tent door (Genesis 18:1).'),
('Genesis', 18, 'teens', 2, 'How did Abraham treat the three visitors?', 'He ignored them', 'He ran to meet them, bowed, washed their feet, and prepared a meal', 'He sent them away', 'He was suspicious of them', 'b', 'Abraham ran to meet them, bowed, offered water, and prepared a feast (Genesis 18:2-8).'),
('Genesis', 18, 'teens', 3, 'Why did Sarah laugh?', 'She was happy about a joke', 'She thought she was too old to have a child', 'She was laughing at Abraham', 'She was nervous', 'b', 'Sarah laughed, saying, "After I am waxed old shall I have pleasure, my lord being old also?" (Genesis 18:12).'),
('Genesis', 18, 'teens', 4, 'What did Abraham plead with God about regarding Sodom?', 'To let him rescue Lot first', 'To spare the city if righteous people were found there', 'To destroy it quickly', 'To send a warning first', 'b', 'Abraham interceded, asking God to spare Sodom for the sake of the righteous (Genesis 18:23-32).'),
('Genesis', 18, 'teens', 5, 'What was the lowest number of righteous people Abraham bargained down to?', 'Fifty', 'Twenty', 'Ten', 'Five', 'c', 'Abraham bargained from fifty down to ten righteous people (Genesis 18:32).'),
-- Adults
('Genesis', 18, 'adults', 1, 'What is the significance of Abraham offering a calf, butter, milk, and cakes to his visitors?', 'It was an ordinary meal', 'It demonstrates lavish Near Eastern hospitality and honor given to the divine visitors', 'He was showing off his wealth', 'It was a required religious offering', 'b', 'Abraham prepared a generous feast, reflecting the highest standard of ancient hospitality (Genesis 18:6-8).'),
('Genesis', 18, 'adults', 2, 'What did the LORD say about why He would not hide His plans from Abraham?', 'Abraham was His prophet', 'Abraham would become a great nation and all nations would be blessed through him', 'Abraham asked Him to share', 'It was common for God to share His plans', 'b', 'The LORD said, "Shall I hide from Abraham that thing which I do, seeing that Abraham shall surely become a great and mighty nation?" (Genesis 18:17-18).'),
('Genesis', 18, 'adults', 3, 'What does God say is the reason He chose Abraham in Genesis 18:19?', 'Because Abraham was perfect', 'That he would command his children to keep the way of the LORD, to do justice and judgment', 'Because Abraham was the oldest patriarch', 'Because Abraham offered the best sacrifices', 'b', 'God said, "I know him, that he will command his children...to keep the way of the LORD, to do justice and judgment" (Genesis 18:19).'),
('Genesis', 18, 'adults', 4, 'What key attribute of God does Abraham appeal to in his intercession for Sodom?', 'God''s power', 'God''s justice — "Shall not the Judge of all the earth do right?"', 'God''s mercy alone', 'God''s patience', 'b', 'Abraham said, "Shall not the Judge of all the earth do right?" (Genesis 18:25).'),
('Genesis', 18, 'adults', 5, 'What does Sarah''s denial of laughing and God''s response reveal?', 'Sarah was honest', 'Even after divine revelation, human weakness (fear and denial) persists, and God sees through it', 'God didn''t mind the laughter', 'Sarah was testing God', 'b', 'Sarah denied, saying, "I laughed not." And he said, "Nay; but thou didst laugh" (Genesis 18:15).'),
('Genesis', 18, 'adults', 6, 'How does Abraham''s intercession for Sodom reflect the biblical role of intercessory prayer?', 'It was unique to Abraham', 'It establishes the pattern of a righteous person interceding for others, a theme that runs through Moses, Samuel, and Christ', 'It shows prayer doesn''t work', 'It was merely a negotiation', 'b', 'Abraham''s bold intercession foreshadows the intercessory role of Moses (Exodus 32) and ultimately Christ (Genesis 18:23-32).'),
('Genesis', 18, 'adults', 7, 'What had the cry of Sodom and Gomorrah become according to God?', 'A whisper', 'Great, and their sin very grievous', 'A plea for help', 'An offering to God', 'b', 'The LORD said, "The cry of Sodom and Gomorrah is great, and their sin is very grievous" (Genesis 18:20).'),
('Genesis', 18, 'adults', 8, 'What does the phrase "Is any thing too hard for the LORD?" in Genesis 18:14 establish theologically?', 'That God sometimes struggles', 'The absolute omnipotence of God — nothing is beyond His power', 'That miracles are rare', 'That God works only through natural means', 'b', '"Is any thing too hard for the LORD?" declares God''s omnipotence and is echoed in Jeremiah 32:17, 27 (Genesis 18:14).');

-- ═══ Genesis Chapter 19 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Genesis', 19, 'kids', 1, 'What two cities did God destroy because of their wickedness?', 'Jerusalem and Bethlehem', 'Sodom and Gomorrah', 'Babel and Nineveh', 'Ur and Haran', 'b', 'The LORD rained upon Sodom and upon Gomorrah brimstone and fire (Genesis 19:24).'),
('Genesis', 19, 'kids', 2, 'Who did the angels help escape from Sodom?', 'Abraham', 'Lot and his family', 'Noah', 'Moses', 'b', 'The angels brought Lot, his wife, and two daughters out of the city (Genesis 19:16).'),
('Genesis', 19, 'kids', 3, 'What happened to Lot''s wife when she looked back?', 'She fell down', 'She became a pillar of salt', 'She got lost', 'She turned invisible', 'b', 'His wife looked back from behind him, and she became a pillar of salt (Genesis 19:26).'),
-- Teens
('Genesis', 19, 'teens', 1, 'Who visited Lot in Sodom?', 'Abraham and his servants', 'Two angels', 'Three strangers', 'The king of Salem', 'b', 'There came two angels to Sodom at even; and Lot sat in the gate of Sodom (Genesis 19:1).'),
('Genesis', 19, 'teens', 2, 'What did the men of Sodom want to do to Lot''s visitors?', 'Welcome them with a feast', 'Harm them and commit wicked acts against them', 'Put them in prison', 'Send them away peacefully', 'b', 'The men of Sodom demanded Lot bring them out "that we may know them" — a demand for violent wickedness (Genesis 19:5).'),
('Genesis', 19, 'teens', 3, 'How did the angels protect Lot from the mob?', 'They called down fire', 'They struck the men with blindness', 'They built a wall', 'They sent a strong wind', 'b', 'The angels smote the men that were at the door with blindness (Genesis 19:11).'),
('Genesis', 19, 'teens', 4, 'What warning did the angels give Lot about the city?', 'Leave by morning', 'The LORD will destroy this place', 'Pay a ransom to escape', 'Hide in the basement', 'b', 'The angels said, "We will destroy this place, because the cry of them is waxen great before the face of the LORD" (Genesis 19:13).'),
('Genesis', 19, 'teens', 5, 'Where did the angels tell Lot to flee to?', 'To Abraham''s camp', 'To the mountain', 'To Egypt', 'To the sea', 'b', 'The angels said, "Escape to the mountain, lest thou be consumed" (Genesis 19:17).'),
-- Adults
('Genesis', 19, 'adults', 1, 'What does Lot''s position "sitting in the gate of Sodom" suggest about his status?', 'He was a guard', 'He held a position of civic authority or prominence', 'He was begging', 'He was waiting for visitors', 'b', 'Sitting in the gate was a sign of civic leadership in ancient cities (Genesis 19:1).'),
('Genesis', 19, 'adults', 2, 'What small city did Lot plead to flee to instead of the mountain?', 'Bethel', 'Zoar', 'Hebron', 'Jericho', 'b', 'Lot said, "This city is near to flee unto, and it is a little one." The name of it was Zoar (Genesis 19:20-22).'),
('Genesis', 19, 'adults', 3, 'What fell upon Sodom and Gomorrah from heaven?', 'A great earthquake', 'Brimstone and fire from the LORD out of heaven', 'A flood of water', 'Hail and lightning', 'b', 'The LORD rained upon Sodom and upon Gomorrah brimstone and fire from the LORD out of heaven (Genesis 19:24).'),
('Genesis', 19, 'adults', 4, 'What did Abraham see when he looked toward Sodom the next morning?', 'Nothing remained', 'The smoke of the country went up as the smoke of a furnace', 'A rainbow over the ruins', 'The city was rebuilt', 'b', 'Abraham looked toward Sodom...and, lo, the smoke of the country went up as the smoke of a furnace (Genesis 19:28).'),
('Genesis', 19, 'adults', 5, 'Why is Lot''s wife becoming a pillar of salt theologically significant?', 'Salt was valuable in that era', 'It illustrates the consequence of disobedience and longing for the sinful world one is told to leave behind', 'It was a natural chemical reaction', 'It had no deeper meaning', 'b', 'Lot''s wife looking back symbolizes attachment to sin and disobedience to God''s command; Jesus references it in Luke 17:32.'),
('Genesis', 19, 'adults', 6, 'What does Genesis 19:29 say was the reason Lot was saved?', 'Lot was righteous enough', 'God remembered Abraham and sent Lot out of the midst of the overthrow', 'Lot prayed for deliverance', 'The angels chose to save him', 'b', 'God remembered Abraham, and sent Lot out of the midst of the overthrow (Genesis 19:29).'),
('Genesis', 19, 'adults', 7, 'What troubling events occurred after Lot fled to the cave in the mountain?', 'He built a new city', 'His daughters got him drunk and bore children by him, giving rise to Moab and Ammon', 'He offered sacrifice and worshipped God', 'He returned to Sodom''s ruins', 'b', 'Lot''s daughters bore sons: Moab (father of the Moabites) and Ben-ammi (father of the Ammonites) (Genesis 19:36-38).'),
('Genesis', 19, 'adults', 8, 'How does the destruction of Sodom serve as a theological archetype in Scripture?', 'It is never referenced again', 'It becomes the standard example of divine judgment on extreme wickedness, referenced by prophets and by Jesus', 'It only applies to that specific situation', 'It was exaggerated in later traditions', 'b', 'Sodom''s destruction is referenced as a paradigm of judgment in Isaiah 1:9, Ezekiel 16:49, Jude 1:7, and by Jesus in Matthew 10:15.');

-- ═══ Genesis Chapter 20 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Genesis', 20, 'kids', 1, 'What king took Sarah because Abraham said she was his sister?', 'Pharaoh', 'Abimelech', 'Nimrod', 'Melchizedek', 'b', 'Abimelech king of Gerar sent, and took Sarah (Genesis 20:2).'),
('Genesis', 20, 'kids', 2, 'How did God warn Abimelech not to keep Sarah?', 'He sent an angel', 'He spoke to him in a dream', 'He sent a plague of locusts', 'He made the sun stop', 'b', 'God came to Abimelech in a dream by night (Genesis 20:3).'),
('Genesis', 20, 'kids', 3, 'Did Abimelech give Sarah back to Abraham?', 'No, he kept her', 'Yes, he returned her safely', 'He asked Abraham to leave', 'He traded her for sheep', 'b', 'Abimelech restored Sarah to Abraham along with gifts (Genesis 20:14).'),
-- Teens
('Genesis', 20, 'teens', 1, 'Why did Abraham once again say Sarah was his sister?', 'Sarah asked him to', 'He feared the people of Gerar would kill him for his wife', 'God told him to test Abimelech', 'He forgot she was his wife', 'b', 'Abraham said, "Because I thought, Surely the fear of God is not in this place; and they will slay me for my wife''s sake" (Genesis 20:11).'),
('Genesis', 20, 'teens', 2, 'What did God threaten Abimelech with in the dream?', 'Losing his kingdom', 'Death, because the woman was a man''s wife', 'A flood upon his land', 'Losing his sight', 'b', 'God said, "Behold, thou art but a dead man, for the woman which thou hast taken; for she is a man''s wife" (Genesis 20:3).'),
('Genesis', 20, 'teens', 3, 'Was Abraham technically lying when he called Sarah his sister?', 'Yes, it was a complete lie', 'No — Sarah was his half-sister, the daughter of his father but not his mother', 'Yes, she was no relation at all', 'It was a cultural custom with no truth', 'b', 'Abraham said, "She is my sister; she is the daughter of my father, but not the daughter of my mother" (Genesis 20:12).'),
('Genesis', 20, 'teens', 4, 'What gifts did Abimelech give Abraham?', 'Gold and jewels', 'Sheep, oxen, servants, and a thousand pieces of silver', 'A large house and land', 'Horses and chariots', 'b', 'Abimelech gave Abraham sheep, oxen, menservants, womenservants, and a thousand pieces of silver (Genesis 20:14-16).'),
('Genesis', 20, 'teens', 5, 'What did Abraham do for Abimelech after Sarah was returned?', 'He blessed his food', 'He prayed to God, and God healed Abimelech and his household', 'He built an altar', 'He gave him sheep', 'b', 'Abraham prayed unto God: and God healed Abimelech, and his wife, and his maidservants (Genesis 20:17).'),
-- Adults
('Genesis', 20, 'adults', 1, 'What had God done to Abimelech''s household because of Sarah?', 'Sent them a famine', 'Closed up all the wombs of his house', 'Struck them with blindness', 'Sent a plague of boils', 'b', 'The LORD had fast closed up all the wombs of the house of Abimelech, because of Sarah (Genesis 20:18).'),
('Genesis', 20, 'adults', 2, 'How did Abimelech defend his integrity before God?', 'He offered sacrifices', 'He said he acted in the integrity of his heart and innocence of his hands', 'He blamed Abraham', 'He promised to build a temple', 'b', 'Abimelech said, "In the integrity of my heart and innocency of my hands have I done this" (Genesis 20:5).'),
('Genesis', 20, 'adults', 3, 'How did God respond to Abimelech''s claim of innocence?', 'God rejected it', 'God confirmed it, saying He knew and had prevented Abimelech from sinning', 'God ignored it', 'God punished him anyway', 'b', 'God said, "I know that thou didst this in the integrity of thy heart; for I also withheld thee from sinning against me" (Genesis 20:6).'),
('Genesis', 20, 'adults', 4, 'What does God call Abraham in Genesis 20:7?', 'A priest', 'A prophet', 'A king', 'A judge', 'b', 'God said to Abimelech, "Restore the man his wife; for he is a prophet, and he shall pray for thee" (Genesis 20:7).'),
('Genesis', 20, 'adults', 5, 'What moral tension does this chapter present regarding Abraham?', 'Abraham was perfectly righteous', 'Abraham, called a prophet by God, repeated the same deception about Sarah that he used in Egypt', 'Abraham was punished for his deception', 'Abimelech was more sinful than Abraham', 'b', 'Abraham repeats the wife-sister deception from Genesis 12, showing even the father of faith struggled with recurring sin.'),
('Genesis', 20, 'adults', 6, 'What does Abimelech''s rebuke of Abraham in Genesis 20:9-10 reveal?', 'Pagans had no moral standards', 'Even a pagan king recognized the moral wrongness of Abraham''s deception', 'Abimelech was a believer in God', 'Abraham was justified in his actions', 'b', 'Abimelech rebuked Abraham: "What hast thou done unto us?...thou hast done deeds unto me that ought not to be done" (Genesis 20:9).'),
('Genesis', 20, 'adults', 7, 'What does the thousand pieces of silver serve as according to Abimelech?', 'Payment for Sarah', 'A covering of the eyes — a vindication of Sarah''s honor', 'A bribe to keep quiet', 'A wedding gift', 'b', 'Abimelech said the silver is "a covering of the eyes, unto all that are with thee, and with all other" (Genesis 20:16).'),
('Genesis', 20, 'adults', 8, 'What does God''s protection of Sarah in this chapter demonstrate about the Abrahamic promise?', 'God protects the wealthy', 'God will preserve the covenant line and the promised heir (Isaac) regardless of human failure', 'God favors Abraham over all others', 'It has no connection to the covenant', 'b', 'God''s intervention protects Sarah — and the yet-unborn Isaac — ensuring the covenant promise is fulfilled despite Abraham''s deception (Genesis 20:6).');

-- ═══════════════════════════════════════════
-- CHAPTERS 21 – 25
-- ═══════════════════════════════════════════

-- ═══ Genesis Chapter 21 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Genesis', 21, 'kids', 1, 'What was the name of Abraham and Sarah''s baby boy?', 'Ishmael', 'Isaac', 'Jacob', 'Joseph', 'b', 'Abraham called the name of his son Isaac (Genesis 21:3).'),
('Genesis', 21, 'kids', 2, 'Why was Sarah so happy when Isaac was born?', 'She received many gifts', 'God had given her a baby in her old age, and she laughed with joy', 'Abraham threw a party', 'Her friends came to visit', 'b', 'Sarah said, "God hath made me to laugh, so that all that hear will laugh with me" (Genesis 21:6).'),
('Genesis', 21, 'kids', 3, 'What did God provide for Hagar and Ishmael in the desert?', 'A tent and food', 'A well of water', 'A tree with fruit', 'A cloud for shade', 'b', 'God opened her eyes, and she saw a well of water (Genesis 21:19).'),
-- Teens
('Genesis', 21, 'teens', 1, 'How old was Abraham when Isaac was born?', 'Ninety years old', 'Ninety-nine years old', 'One hundred years old', 'One hundred and five years old', 'c', 'Abraham was an hundred years old, when his son Isaac was born unto him (Genesis 21:5).'),
('Genesis', 21, 'teens', 2, 'Why did Sarah want Hagar and Ishmael sent away?', 'Hagar was stealing from them', 'She saw Ishmael mocking, and did not want him to inherit with Isaac', 'God commanded her to', 'Abraham wanted more space', 'b', 'Sarah saw the son of Hagar mocking, and said, "Cast out this bondwoman and her son: for the son of this bondwoman shall not be heir with my son" (Genesis 21:9-10).'),
('Genesis', 21, 'teens', 3, 'How did Abraham feel about sending Ishmael away?', 'He was indifferent', 'It was very grievous to him', 'He was relieved', 'He was angry at Sarah', 'b', 'The thing was very grievous in Abraham''s sight because of his son (Genesis 21:11).'),
('Genesis', 21, 'teens', 4, 'What did God promise Abraham about Ishmael?', 'Ishmael would return someday', 'God would make him a nation because he was Abraham''s seed', 'Ishmael would inherit Canaan', 'Ishmael would become a priest', 'b', 'God said, "Also of the son of the bondwoman will I make a nation, because he is thy seed" (Genesis 21:13).'),
('Genesis', 21, 'teens', 5, 'What did Abraham and Abimelech do at Beersheba?', 'They fought a battle', 'They made a covenant and swore an oath of peace', 'They built a temple', 'They shared a harvest', 'b', 'Abraham and Abimelech made a covenant at Beersheba (Genesis 21:27, 31).'),
-- Adults
('Genesis', 21, 'adults', 1, 'On what day was Isaac circumcised according to God''s command?', 'The first day', 'The eighth day', 'The thirteenth day', 'The thirtieth day', 'b', 'Abraham circumcised his son Isaac being eight days old, as God had commanded him (Genesis 21:4).'),
('Genesis', 21, 'adults', 2, 'What does Paul interpret Hagar and Sarah as representing in Galatians 4?', 'Two different nations', 'Two covenants — Hagar represents the old covenant of law, Sarah the new covenant of promise', 'Two different time periods', 'Two aspects of God''s character', 'b', 'Paul uses Hagar (bondage/law) and Sarah (freedom/promise) as an allegory of the two covenants (Galatians 4:22-31; Genesis 21:10).'),
('Genesis', 21, 'adults', 3, 'What does the name Beersheba mean?', 'Well of living water', 'Well of the oath (or well of seven)', 'Well of peace', 'Well of blessing', 'b', 'Beersheba means "well of the oath" or "well of seven" — Abraham and Abimelech swore there and Abraham set apart seven ewe lambs (Genesis 21:31).'),
('Genesis', 21, 'adults', 4, 'What kind of tree did Abraham plant at Beersheba?', 'An olive tree', 'A grove (tamarisk tree)', 'A fig tree', 'A palm tree', 'b', 'Abraham planted a grove (tamarisk tree) in Beersheba, and called there on the name of the LORD (Genesis 21:33).'),
('Genesis', 21, 'adults', 5, 'What name of God did Abraham call upon at Beersheba?', 'El Shaddai', 'The everlasting God (El Olam)', 'El Elyon', 'Jehovah Jireh', 'b', 'Abraham called there on the name of the LORD, the everlasting God (El Olam) (Genesis 21:33).'),
('Genesis', 21, 'adults', 6, 'Why did God tell Abraham to listen to Sarah regarding Ishmael?', 'Sarah was always right', 'Because in Isaac shall thy seed be called — the covenant line must go through Isaac', 'Sarah had seniority', 'Ishmael was a troublemaker', 'b', 'God said, "In all that Sarah hath said unto thee, hearken unto her voice; for in Isaac shall thy seed be called" (Genesis 21:12).'),
('Genesis', 21, 'adults', 7, 'What dispute with Abimelech prompted the covenant at Beersheba?', 'A border dispute', 'Abimelech''s servants had seized Abraham''s well', 'A conflict over grazing land', 'A trade disagreement', 'b', 'Abraham reproved Abimelech because of a well of water, which Abimelech''s servants had violently taken away (Genesis 21:25).'),
('Genesis', 21, 'adults', 8, 'What role did the seven ewe lambs play in the covenant at Beersheba?', 'They were a sacrifice to God', 'They served as witness that Abraham had dug the well', 'They were a gift for Abimelech''s family', 'They were payment for the land', 'b', 'Abraham set seven ewe lambs by themselves as a witness that he had dug the well (Genesis 21:28-30).');

-- ═══ Genesis Chapter 22 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Genesis', 22, 'kids', 1, 'What did God ask Abraham to offer on the mountain?', 'A lamb', 'His son Isaac', 'A goat', 'His best ox', 'b', 'God said, "Take now thy son, thine only son Isaac...and offer him for a burnt offering" (Genesis 22:2).'),
('Genesis', 22, 'kids', 2, 'What did Abraham find caught in the bushes?', 'A lamb', 'A ram', 'A goat', 'A dove', 'b', 'Abraham looked and behold behind him a ram caught in a thicket by his horns (Genesis 22:13).'),
('Genesis', 22, 'kids', 3, 'Did Abraham have to sacrifice Isaac?', 'Yes', 'No — God provided a ram instead', 'Yes, but Isaac came back to life', 'No — Isaac ran away', 'b', 'The angel of the LORD stopped Abraham, and God provided a ram in Isaac''s place (Genesis 22:11-13).'),
-- Teens
('Genesis', 22, 'teens', 1, 'Where did God tell Abraham to take Isaac for the offering?', 'Mount Sinai', 'The land of Moriah', 'Beersheba', 'The plains of Mamre', 'b', 'God said, "Get thee into the land of Moriah; and offer him there for a burnt offering" (Genesis 22:2).'),
('Genesis', 22, 'teens', 2, 'What did Isaac ask his father on the way up the mountain?', 'Are we there yet?', 'Where is the lamb for the burnt offering?', 'Why are we going to the mountain?', 'Can I carry the wood?', 'b', 'Isaac said, "Behold the fire and the wood: but where is the lamb for a burnt offering?" (Genesis 22:7).'),
('Genesis', 22, 'teens', 3, 'What was Abraham''s famous answer about the lamb?', 'We will find one on the way', 'God will provide himself a lamb', 'I forgot to bring one', 'We don''t need one', 'b', 'Abraham said, "My son, God will provide himself a lamb for a burnt offering" (Genesis 22:8).'),
('Genesis', 22, 'teens', 4, 'What stopped Abraham from sacrificing Isaac?', 'Isaac cried out', 'The angel of the LORD called from heaven and said "Lay not thine hand upon the lad"', 'Sarah arrived and stopped him', 'It started to rain', 'b', 'The angel of the LORD called unto him out of heaven, and said, "Lay not thine hand upon the lad" (Genesis 22:11-12).'),
('Genesis', 22, 'teens', 5, 'What name did Abraham give the place?', 'Bethel', 'Jehovah-jireh (The LORD will provide)', 'Beersheba', 'Peniel', 'b', 'Abraham called the name of that place Jehovah-jireh: "In the mount of the LORD it shall be seen" (Genesis 22:14).'),
-- Adults
('Genesis', 22, 'adults', 1, 'What Hebrew word is used for what God did to Abraham in Genesis 22:1?', 'Judged', 'Tempted (tested/proved)', 'Blessed', 'Called', 'b', 'God did tempt (Hebrew: nissah — tested/proved) Abraham (Genesis 22:1).'),
('Genesis', 22, 'adults', 2, 'How does the binding of Isaac (Aqedah) foreshadow the sacrifice of Christ?', 'It does not relate to Christ', 'The beloved only son, carrying wood up a mount, willingly submitted, and God provided a substitute — paralleling Christ on the cross', 'It only illustrates obedience', 'It foreshadows the temple sacrifices', 'b', 'Isaac as the beloved son carrying wood up Moriah, willingly submitted, and a substitute was provided — all foreshadow Christ (Genesis 22:2, 6, 13).'),
('Genesis', 22, 'adults', 3, 'What does Hebrews 11:17-19 say about Abraham''s mindset during this test?', 'Abraham was terrified', 'Abraham accounted that God was able to raise Isaac from the dead', 'Abraham doubted but obeyed', 'Abraham planned to find a substitute', 'b', 'By faith Abraham offered up Isaac, accounting that God was able to raise him up, even from the dead (Hebrews 11:17-19).'),
('Genesis', 22, 'adults', 4, 'What is the significance of Mount Moriah in later biblical history?', 'It became a Roman fortress', 'It is traditionally identified as the site where Solomon built the temple', 'It is where Moses received the Law', 'It is where David was anointed', 'b', 'Mount Moriah is identified with the temple mount in Jerusalem (Genesis 22:2; cf. 2 Chronicles 3:1).'),
('Genesis', 22, 'adults', 5, 'What new promise did God add after Abraham passed the test?', 'A longer life', 'His seed would possess the gate of his enemies, and in his seed all nations would be blessed', 'Immediate possession of Canaan', 'A hundred sons', 'b', 'God said, "Thy seed shall possess the gate of his enemies; and in thy seed shall all the nations of the earth be blessed" (Genesis 22:17-18).'),
('Genesis', 22, 'adults', 6, 'What reason did God give for why He now blessed Abraham?', 'Because Abraham was wealthy', 'Because thou hast obeyed my voice and hast not withheld thy son, thine only son', 'Because Abraham built many altars', 'Because Abraham was the oldest patriarch', 'b', 'God said, "Because thou hast done this thing, and hast not withheld thy son, thine only son" (Genesis 22:16).'),
('Genesis', 22, 'adults', 7, 'What prophetic significance does Abraham''s statement "God will provide himself a lamb" carry?', 'It refers only to the ram in the thicket', 'It ultimately points to Christ as the Lamb of God whom God Himself provides', 'It was an empty reassurance to Isaac', 'It refers to the Passover lamb only', 'b', '"God will provide himself a lamb" (Genesis 22:8) finds ultimate fulfillment in John 1:29: "Behold the Lamb of God."'),
('Genesis', 22, 'adults', 8, 'How does Genesis 22:12 describe what God now knows about Abraham?', 'That Abraham is wealthy', 'That Abraham fears God and would not withhold his only son', 'That Abraham is a prophet', 'That Abraham is the father of many nations', 'b', 'God said, "Now I know that thou fearest God, seeing thou hast not withheld thy son, thine only son from me" (Genesis 22:12).');

-- ═══ Genesis Chapter 23 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Genesis', 23, 'kids', 1, 'Who died in this chapter?', 'Abraham', 'Hagar', 'Sarah', 'Isaac', 'c', 'Sarah was an hundred and seven and twenty years old...and Sarah died (Genesis 23:1-2).'),
('Genesis', 23, 'kids', 2, 'How old was Sarah when she died?', 'One hundred years old', 'One hundred and twenty-seven years old', 'Ninety years old', 'One hundred and fifty years old', 'b', 'Sarah was an hundred and seven and twenty years old (Genesis 23:1).'),
('Genesis', 23, 'kids', 3, 'What did Abraham buy to bury Sarah?', 'A garden', 'A cave called Machpelah', 'A field by the river', 'A tomb in a city', 'b', 'Abraham buried Sarah in the cave of the field of Machpelah (Genesis 23:19).'),
-- Teens
('Genesis', 23, 'teens', 1, 'Where did Sarah die?', 'In Beersheba', 'In Kirjath-arba, which is Hebron', 'In Egypt', 'In Ur', 'b', 'Sarah died in Kirjath-arba; the same is Hebron in the land of Canaan (Genesis 23:2).'),
('Genesis', 23, 'teens', 2, 'Who owned the cave of Machpelah before Abraham bought it?', 'Abimelech', 'Ephron the Hittite', 'Melchizedek', 'Lot', 'b', 'Abraham spoke to Ephron the Hittite to buy the cave of Machpelah (Genesis 23:8-9).'),
('Genesis', 23, 'teens', 3, 'How much did Abraham pay for the field and cave?', 'Two hundred shekels of silver', 'Four hundred shekels of silver', 'A thousand pieces of gold', 'He received it as a gift', 'b', 'Abraham weighed to Ephron four hundred shekels of silver (Genesis 23:16).'),
('Genesis', 23, 'teens', 4, 'What did the children of Heth initially offer Abraham?', 'To sell him any land he wanted', 'To let him bury Sarah in any of their sepulchres', 'To build him a new tomb', 'To embalm Sarah for him', 'b', 'The children of Heth said, "In the choice of our sepulchres bury thy dead" (Genesis 23:6).'),
('Genesis', 23, 'teens', 5, 'Why was it important that Abraham purchased the land rather than accepting a gift?', 'He had too much money', 'He wanted undisputed legal ownership of the burial site in the Promised Land', 'He didn''t trust the Hittites', 'He wanted to show off his wealth', 'b', 'Abraham insisted on paying so he would have legal, permanent ownership of land in Canaan (Genesis 23:13).'),
-- Adults
('Genesis', 23, 'adults', 1, 'What does Abraham call himself among the Hittites?', 'A king and ruler', 'A stranger and a sojourner', 'A prophet of God', 'A wealthy merchant', 'b', 'Abraham said, "I am a stranger and a sojourner with you" (Genesis 23:4).'),
('Genesis', 23, 'adults', 2, 'What is the theological significance of Machpelah as the first real estate purchase in the Promised Land?', 'It was merely a practical need', 'It represents the first tangible stake in the Promised Land, a down payment on God''s promise of the whole land', 'It shows Abraham was wealthy', 'It was a temporary arrangement', 'b', 'Machpelah is the first piece of the Promised Land Abraham actually owned, a concrete step toward the fulfillment of God''s land promise.'),
('Genesis', 23, 'adults', 3, 'Who else was eventually buried at Machpelah besides Sarah?', 'Only Isaac', 'Abraham, Isaac, Rebekah, Jacob, and Leah', 'Only Abraham and Sarah', 'All twelve sons of Jacob', 'b', 'Machpelah became the family burial site for Abraham, Isaac, Rebekah, Jacob, and Leah (Genesis 49:29-31; 50:13).'),
('Genesis', 23, 'adults', 4, 'What ancient Near Eastern custom is reflected in the negotiation between Abraham and Ephron?', 'A simple cash transaction', 'The public offer of a "gift" with the expectation of payment — a polite bargaining protocol', 'A trade of goods for goods', 'A legal contract written on parchment', 'b', 'Ephron''s offer to give the field for free was the ancient Near Eastern protocol — the expectation was that Abraham would insist on paying (Genesis 23:11-16).'),
('Genesis', 23, 'adults', 5, 'Where in Canaan is Hebron located?', 'In the northern Galilee region', 'In the southern hill country of Judah', 'On the Mediterranean coast', 'In the Jordan valley', 'b', 'Hebron (Kirjath-arba) is located in the southern hill country of Judah (Genesis 23:2).'),
('Genesis', 23, 'adults', 6, 'What phrase indicates that the transaction was legally binding and public?', 'They shook hands', 'Abraham weighed the silver "current money with the merchant" in the audience of the sons of Heth', 'They signed a contract', 'They called for witnesses from another city', 'b', 'Abraham weighed four hundred shekels of silver, current money with the merchant, in the audience of the sons of Heth (Genesis 23:16).'),
('Genesis', 23, 'adults', 7, 'What items were included in the purchase beyond the cave itself?', 'Only the cave', 'The field, the cave, and all the trees in the field', 'The cave and surrounding pastureland', 'The cave, a well, and livestock', 'b', 'The field, and the cave therein, and all the trees that were in the field...were made sure unto Abraham (Genesis 23:17).'),
('Genesis', 23, 'adults', 8, 'What does the phrase "children of Heth" refer to?', 'A Hebrew tribe', 'The Hittites, descendants of Heth son of Canaan', 'Egyptian settlers', 'Nomadic traders', 'b', 'The children of Heth are the Hittites, descended from Heth, a son of Canaan (Genesis 23:3; cf. 10:15).');

-- ═══ Genesis Chapter 24 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Genesis', 24, 'kids', 1, 'Who did Abraham send his servant to find?', 'A new land to live in', 'A wife for his son Isaac', 'More sheep and goats', 'A place to build a temple', 'b', 'Abraham told his servant to go to his kindred and take a wife for Isaac (Genesis 24:4).'),
('Genesis', 24, 'kids', 2, 'What was the name of the woman the servant found at the well?', 'Rachel', 'Leah', 'Rebekah', 'Sarah', 'c', 'The damsel''s name was Rebekah (Genesis 24:15).'),
('Genesis', 24, 'kids', 3, 'What kind thing did Rebekah do for the servant?', 'She cooked him a meal', 'She gave him water and watered his camels too', 'She gave him gold', 'She invited him to a party', 'b', 'Rebekah gave him drink and said, "I will draw water for thy camels also" (Genesis 24:18-19).'),
-- Teens
('Genesis', 24, 'teens', 1, 'What oath did Abraham make his servant swear?', 'To never leave his service', 'Not to take a wife for Isaac from the Canaanites, but from Abraham''s own family', 'To find the wealthiest bride', 'To return to Ur of the Chaldees', 'b', 'Abraham said, "Thou shalt not take a wife unto my son of the daughters of the Canaanites...but thou shalt go unto my country, and to my kindred" (Genesis 24:3-4).'),
('Genesis', 24, 'teens', 2, 'What sign did the servant pray for to identify the right woman?', 'She would be the most beautiful', 'She would offer water to him and his camels', 'She would be wearing a red veil', 'She would be standing under a tree', 'b', 'The servant prayed that the damsel who offered to water his camels would be the one God appointed for Isaac (Genesis 24:14).'),
('Genesis', 24, 'teens', 3, 'Who was Rebekah''s father?', 'Laban', 'Bethuel', 'Nahor', 'Terah', 'b', 'Rebekah was the daughter of Bethuel son of Milcah, the wife of Nahor (Genesis 24:15).'),
('Genesis', 24, 'teens', 4, 'What gifts did the servant give Rebekah?', 'Robes and sandals', 'A golden earring and two bracelets', 'Silver coins and cloth', 'A camel and fine food', 'b', 'The man took a golden earring of half a shekel weight, and two bracelets for her hands (Genesis 24:22).'),
('Genesis', 24, 'teens', 5, 'What was Rebekah''s answer when asked if she would go with the servant?', 'She said no', 'She said, "I will go"', 'She asked for more time', 'She asked her father to decide', 'b', 'They called Rebekah, and said, "Wilt thou go with this man?" And she said, "I will go" (Genesis 24:58).'),
-- Adults
('Genesis', 24, 'adults', 1, 'Where did Abraham make his servant place his hand when swearing the oath?', 'On Abraham''s head', 'Under Abraham''s thigh', 'On an altar', 'On the Torah', 'b', 'Abraham said, "Put thy hand under my thigh" — an ancient oath gesture signifying the most solemn vow (Genesis 24:2).'),
('Genesis', 24, 'adults', 2, 'What did Abraham insist must NOT happen if the woman was unwilling to come?', 'The servant should take Isaac there anyway', 'Isaac must not be brought back to Mesopotamia', 'The servant should force her to come', 'The engagement should be called off permanently', 'b', 'Abraham said, "Beware thou that thou bring not my son thither again" — Isaac must remain in Canaan (Genesis 24:6, 8).'),
('Genesis', 24, 'adults', 3, 'How many camels did the servant take on the journey?', 'Two', 'Five', 'Ten', 'Twenty', 'c', 'The servant took ten camels of the camels of his master and departed (Genesis 24:10).'),
('Genesis', 24, 'adults', 4, 'What city did the servant travel to?', 'Ur of the Chaldees', 'The city of Nahor in Mesopotamia', 'Haran in Syria', 'Damascus', 'b', 'The servant went to Mesopotamia, unto the city of Nahor (Genesis 24:10).'),
('Genesis', 24, 'adults', 5, 'What was Laban''s role in the negotiations, and what motivated his hospitality?', 'He was indifferent to the servant', 'Laban ran to greet the servant after seeing the golden jewelry on Rebekah', 'Laban refused to let Rebekah go', 'Laban demanded payment', 'b', 'When Laban saw the earring and bracelets, he ran to the man and said, "Come in, thou blessed of the LORD" (Genesis 24:30-31).'),
('Genesis', 24, 'adults', 6, 'What blessing did Rebekah''s family pronounce upon her as she departed?', 'May you find happiness', 'Be thou the mother of thousands of millions, and let thy seed possess the gate of those which hate them', 'May you have many sons', 'May God protect you on the journey', 'b', 'They blessed Rebekah: "Be thou the mother of thousands of millions, and let thy seed possess the gate of those which hate them" (Genesis 24:60).'),
('Genesis', 24, 'adults', 7, 'What was Isaac doing when Rebekah first saw him?', 'Working in a field', 'Meditating in the field in the evening', 'Tending sheep', 'Praying at an altar', 'b', 'Isaac went out to meditate in the field at the eventide (Genesis 24:63).'),
('Genesis', 24, 'adults', 8, 'What does Genesis 24:67 say about Isaac''s response to Rebekah?', 'He was indifferent', 'Isaac loved her, and was comforted after his mother''s death', 'He was disappointed', 'He praised God aloud', 'b', 'Isaac brought her into his mother Sarah''s tent, and took Rebekah, and she became his wife; and he loved her: and Isaac was comforted after his mother''s death (Genesis 24:67).');

-- ═══ Genesis Chapter 25 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Genesis', 25, 'kids', 1, 'What were the names of Isaac and Rebekah''s twin boys?', 'Cain and Abel', 'Shem and Ham', 'Jacob and Esau', 'Moses and Aaron', 'c', 'The first came out red and hairy, they called him Esau; and his brother they called Jacob (Genesis 25:25-26).'),
('Genesis', 25, 'kids', 2, 'What did Esau sell to Jacob?', 'His sheep', 'His birthright', 'His coat', 'His tent', 'b', 'Esau sold his birthright unto Jacob (Genesis 25:33).'),
('Genesis', 25, 'kids', 3, 'What food did Jacob give Esau in exchange?', 'Bread and cheese', 'Bread and pottage of lentiles (stew)', 'Fish and bread', 'Roasted meat', 'b', 'Jacob gave Esau bread and pottage of lentiles (Genesis 25:34).'),
-- Teens
('Genesis', 25, 'teens', 1, 'How old was Abraham when he died?', 'One hundred and fifty years old', 'One hundred and seventy-five years old', 'Two hundred years old', 'One hundred and fifty-seven years old', 'b', 'Abraham gave up the ghost and died in a good old age...an hundred threescore and fifteen years (Genesis 25:7-8).'),
('Genesis', 25, 'teens', 2, 'Where was Abraham buried?', 'At Beersheba', 'In the cave of Machpelah', 'On Mount Moriah', 'In Ur of the Chaldees', 'b', 'His sons Isaac and Ishmael buried him in the cave of Machpelah (Genesis 25:9).'),
('Genesis', 25, 'teens', 3, 'What did God tell Rebekah about the twins before they were born?', 'Both would be kings', 'Two nations were in her womb, and the elder would serve the younger', 'They would always be friends', 'The firstborn would be a priest', 'b', 'The LORD said, "Two nations are in thy womb...and the elder shall serve the younger" (Genesis 25:23).'),
('Genesis', 25, 'teens', 4, 'What was Esau like compared to Jacob?', 'They were exactly alike', 'Esau was a skillful hunter and outdoorsman; Jacob was a quiet man dwelling in tents', 'Jacob was the stronger one', 'Esau was a farmer and Jacob was a shepherd', 'b', 'Esau was a cunning hunter, a man of the field; and Jacob was a plain man, dwelling in tents (Genesis 25:27).'),
('Genesis', 25, 'teens', 5, 'Why did Esau sell his birthright?', 'He was forced to', 'He was extremely hungry and despised his birthright', 'He didn''t know its value', 'Jacob threatened him', 'b', 'Esau said, "I am at the point to die: and what profit shall this birthright do to me?" He despised his birthright (Genesis 25:32, 34).'),
-- Adults
('Genesis', 25, 'adults', 1, 'Who was Keturah, and what is her significance?', 'She was Abraham''s mother', 'She was Abraham''s wife after Sarah''s death, and bore him six sons', 'She was Isaac''s second wife', 'She was Hagar''s sister', 'b', 'Abraham took a wife, and her name was Keturah, and she bare him Zimran, Jokshan, Medan, Midian, Ishbak, and Shuah (Genesis 25:1-2).'),
('Genesis', 25, 'adults', 2, 'How many sons did Ishmael have, fulfilling God''s promise?', 'Seven', 'Ten', 'Twelve', 'Fifteen', 'c', 'Ishmael had twelve sons — twelve princes according to their nations, fulfilling Genesis 17:20 (Genesis 25:13-16).'),
('Genesis', 25, 'adults', 3, 'How old was Ishmael when he died?', 'One hundred and twenty years', 'One hundred and thirty-seven years', 'One hundred and fifty years', 'One hundred and seventy-five years', 'b', 'These are the years of the life of Ishmael, an hundred and thirty and seven years (Genesis 25:17).'),
('Genesis', 25, 'adults', 4, 'What does the name Jacob mean, and why was he so named?', 'Faithful one — because he was faithful', 'Supplanter (heel-catcher) — because he took hold of Esau''s heel at birth', 'Beloved — because his mother loved him', 'Chosen — because God chose him', 'b', 'His name was called Jacob because his hand took hold on Esau''s heel (Genesis 25:26). Jacob means "heel-catcher" or "supplanter."'),
('Genesis', 25, 'adults', 5, 'What does Romans 9:10-13 teach about God''s statement regarding Jacob and Esau?', 'God loved both equally', 'God''s election was made before the twins were born or had done good or evil, demonstrating sovereign choice', 'God chose based on their future deeds', 'It only applied to the nations, not the individuals', 'b', 'Paul cites "the elder shall serve the younger" to illustrate God''s sovereign election before birth (Romans 9:10-13; Genesis 25:23).'),
('Genesis', 25, 'adults', 6, 'What does Hebrews 12:16 call Esau for selling his birthright?', 'A fool', 'A profane person who for one morsel of meat sold his birthright', 'An unbeliever', 'A sinner', 'b', 'Hebrews 12:16 calls Esau a "profane person, who for one morsel of meat sold his birthright."'),
('Genesis', 25, 'adults', 7, 'What did Abraham give to Isaac versus the sons of Keturah and the concubines?', 'He divided everything equally', 'Abraham gave all that he had unto Isaac, but gave gifts to the other sons and sent them away', 'He gave more to the sons of Keturah', 'He gave everything to Ishmael', 'b', 'Abraham gave all that he had unto Isaac. But unto the sons of the concubines, Abraham gave gifts, and sent them away (Genesis 25:5-6).'),
('Genesis', 25, 'adults', 8, 'How old was Isaac when Esau and Jacob were born?', 'Forty years old', 'Fifty years old', 'Sixty years old', 'Seventy years old', 'c', 'Isaac was threescore years old when she bare them (Genesis 25:26).');
